{
  "name": "LZRYEK 癫痫管理随访系统",
  "description": "一个基于国际癫痫指南（ILAE/NICE）构建的专业癫痫病人管理与随访系统，支持信息录入、多维度查询及智能随访提醒功能。",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Gender {
  MALE = '男',
  FEMALE = '女'
}

export enum SeizureType {
  FOCAL = '局灶性发作',
  GENERALIZED = '全面性发作',
  UNKNOWN = '未知类型发作'
}

export interface Patient {
  id: string;
  name: string;
  gender: Gender;
  age: number;
  idCard: string;
  phone: string;
  clinicalSummary: {
    seizureType: string;
    eeg: string;
    mri: string;
    genetic: string;
    other: string;
  };
  diagnosis: string;
  diagnosisDate: string;
  medications: Medication[];
  followUpConfig: {
    items: string[];
    intervalMonths: number;
    lastFollowUpDate: string;
    nextFollowUpDate: string;
  };
  createdAt: number;
}

export interface Medication {
  name: string;
  dosage: string;
}

export interface FollowUpReminder {
  patientId: string;
  patientName: string;
  daysRemaining: number;
  isOverdue: boolean;
  dueDate: string;
}

import { Patient } from '../types';

const STORAGE_KEY = 'LZRYEK_EPILEPSY_PATIENTS';

export const storage = {
  getPatients: (): Patient[] => {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },

  savePatients: (patients: Patient[]): void => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(patients));
  },

  addPatient: (patient: Patient): void => {
    const patients = storage.getPatients();
    patients.push(patient);
    storage.savePatients(patients);
  },

  updatePatient: (updatedPatient: Patient): void => {
    const patients = storage.getPatients();
    const index = patients.findIndex(p => p.id === updatedPatient.id);
    if (index !== -1) {
      patients[index] = updatedPatient;
      storage.savePatients(patients);
    }
  },

  deletePatient: (id: string): void => {
    const patients = storage.getPatients();
    const filtered = patients.filter(p => p.id !== id);
    storage.savePatients(filtered);
  }
};

import React, { useState, useEffect } from 'react';
import { Patient, Gender, Medication } from '../types';
import { COMMON_MEDICATIONS, FOLLOW_UP_ITEMS } from '../constants';

interface PatientFormProps {
  initialData?: Patient;
  onSubmit: (data: Patient) => void;
  onCancel: () => void;
}

const PatientForm: React.FC<PatientFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '',
    gender: Gender.MALE,
    age: 0,
    idCard: '',
    phone: '',
    clinicalSummary: {
      seizureType: '',
      eeg: '',
      mri: '',
      genetic: '',
      other: ''
    },
    diagnosis: '',
    diagnosisDate: new Date().toISOString().split('T')[0],
    medications: [{ name: '', dosage: '' }],
    followUpConfig: {
      items: [],
      intervalMonths: 3,
      lastFollowUpDate: new Date().toISOString().split('T')[0],
      nextFollowUpDate: ''
    }
  });

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    }
  }, [initialData]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({
        ...prev,
        [parent]: {
          ...(prev[parent as keyof Patient] as any),
          [child]: value
        }
      }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleMedicationChange = (index: number, field: keyof Medication, value: string) => {
    const newMeds = [...(formData.medications || [])];
    newMeds[index] = { ...newMeds[index], [field]: value };
    setFormData(prev => ({ ...prev, medications: newMeds }));
  };

  const toggleFollowUpItem = (item: string) => {
    const currentItems = formData.followUpConfig?.items || [];
    const newItems = currentItems.includes(item)
      ? currentItems.filter(i => i !== item)
      : [...currentItems, item];

    setFormData(prev => ({
      ...prev,
      followUpConfig: {
        ...prev.followUpConfig!,
        items: newItems
      }
    }));
  };

  const calculateNextDate = () => {
    if (!formData.followUpConfig?.lastFollowUpDate || !formData.followUpConfig?.intervalMonths) return;
    const lastDate = new Date(formData.followUpConfig.lastFollowUpDate);
    lastDate.setMonth(lastDate.getMonth() + Number(formData.followUpConfig.intervalMonths));
    const nextDate = lastDate.toISOString().split('T')[0];

    setFormData(prev => ({
      ...prev,
      followUpConfig: {
        ...prev.followUpConfig!,
        nextFollowUpDate: nextDate
      }
    }));
  };

  useEffect(() => {
    calculateNextDate();
  }, [formData.followUpConfig?.lastFollowUpDate, formData.followUpConfig?.intervalMonths]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalData: Patient = {
      ...(formData as Patient),
      id: initialData?.id || crypto.randomUUID(),
      createdAt: initialData?.createdAt || Date.now(),
    };
    onSubmit(finalData);
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-xl shadow-lg space-y-8 animate-fade-in overflow-y-auto max-h-[85vh]">
      <div className="flex justify-between items-center border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">{initialData ? '修改病人信息' : '录入新病人信息'}</h2>
        <button type="button" onClick={onCancel} className="text-gray-400 hover:text-gray-600">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
      </div>

      {/* 基础信息 */}
      <section>
        <h3 className="text-lg font-semibold text-green-600 mb-4 flex items-center">
          <span className="w-2 h-6 bg-green-500 rounded mr-2"></span> 基础信息
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
          <div className="col-span-1">
            <label className="block text-sm font-medium text-gray-700 mb-1">姓名</label>
            <input name="name" value={formData.name} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-green-500 outline-none" required />
          </div>
          <div className="col-span-1">
            <label className="block text-sm font-medium text-gray-700 mb-1">性别</label>
            <select name="gender" value={formData.gender} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-green-500 outline-none">
              <option value={Gender.MALE}>男</option>
              <option value={Gender.FEMALE}>女</option>
            </select>
          </div>
          <div className="col-span-1">
            <label className="block text-sm font-medium text-gray-700 mb-1">年龄</label>
            <input type="number" name="age" value={formData.age} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-green-500 outline-none" required />
          </div>
          <div className="col-span-1">
            <label className="block text-sm font-medium text-gray-700 mb-1">身份证</label>
            <input name="idCard" value={formData.idCard} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-green-500 outline-none" required />
          </div>
          <div className="col-span-1">
            <label className="block text-sm font-medium text-gray-700 mb-1">电话</label>
            <input name="phone" value={formData.phone} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-green-500 outline-none" required />
          </div>
        </div>
      </section>

      {/* 病情概况与诊断 */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <section className="p-4 border border-green-200 rounded-xl bg-green-50">
          <h3 className="text-lg font-semibold text-green-700 mb-4">病情概况</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">发作形式</label>
              <input name="clinicalSummary.seizureType" value={formData.clinicalSummary?.seizureType} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg" placeholder="如：局灶性演变为全面性" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">脑电图 (EEG)</label>
              <textarea name="clinicalSummary.eeg" value={formData.clinicalSummary?.eeg} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg h-20" placeholder="EEG结果摘要" />
            </div>
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">MRI</label>
                <input name="clinicalSummary.mri" value={formData.clinicalSummary?.mri} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">基因</label>
                <input name="clinicalSummary.genetic" value={formData.clinicalSummary?.genetic} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg" />
              </div>
            </div>
          </div>
        </section>

        <section className="space-y-6">
          <div>
            <h3 className="text-lg font-semibold text-gray-800 mb-2">诊断</h3>
            <input name="diagnosis" value={formData.diagnosis} onChange={handleInputChange} className="w-full px-3 py-2 border-2 border-green-500 rounded-lg focus:ring-4 focus:ring-green-100 outline-none text-lg" placeholder="临床诊断名称" required />
          </div>
          <div>
            <h3 className="text-lg font-semibold text-gray-800 mb-2">诊断时间</h3>
            <input type="date" name="diagnosisDate" value={formData.diagnosisDate} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg outline-none" required />
          </div>
        </section>
      </div>

      {/* 用药情况 */}
      <section>
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-lg font-semibold text-green-600 flex items-center">
            <span className="w-2 h-6 bg-green-500 rounded mr-2"></span> 用药情况
          </h3>
          <button type="button" onClick={() => setFormData(prev => ({ ...prev, medications: [...(prev.medications || []), { name: '', dosage: '' }] }))} className="text-sm bg-green-100 text-green-700 px-3 py-1 rounded-full hover:bg-green-200 transition">
            + 添加药物
          </button>
        </div>
        <div className="space-y-3">
          {(formData.medications || []).map((med, idx) => (
            <div key={idx} className="flex gap-4 items-end">
              <div className="flex-1">
                <label className="block text-xs text-gray-500 mb-1">药物名称 (勾选/搜索)</label>
                <input list="med-suggestions" value={med.name} onChange={(e) => handleMedicationChange(idx, 'name', e.target.value)} className="w-full px-3 py-2 border rounded-lg" placeholder="选择或输入" />
                <datalist id="med-suggestions">
                  {COMMON_MEDICATIONS.map(m => <option key={m} value={m} />)}
                </datalist>
              </div>
              <div className="flex-1">
                <label className="block text-xs text-gray-500 mb-1">剂量及用法</label>
                <input value={med.dosage} onChange={(e) => handleMedicationChange(idx, 'dosage', e.target.value)} className="w-full px-3 py-2 border rounded-lg" placeholder="如：500mg bid" />
              </div>
              {idx > 0 && (
                <button type="button" onClick={() => setFormData(prev => ({ ...prev, medications: prev.medications?.filter((_, i) => i !== idx) }))} className="p-2 text-red-500 hover:bg-red-50 rounded-lg">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                </button>
              )}
            </div>
          ))}
        </div>
      </section>

      {/* 随访设置 */}
      <section className="bg-gray-50 p-6 rounded-xl border border-gray-200">
        <h3 className="text-lg font-semibold text-gray-800 mb-4">随访管理</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">随访项目 (勾选)</label>
            <div className="grid grid-cols-2 gap-2">
              {FOLLOW_UP_ITEMS.map(item => (
                <label key={item} className="flex items-center space-x-2 text-sm cursor-pointer p-2 hover:bg-white rounded border border-transparent hover:border-green-200">
                  <input type="checkbox" checked={formData.followUpConfig?.items.includes(item)} onChange={() => toggleFollowUpItem(item)} className="rounded text-green-500 focus:ring-green-500" />
                  <span>{item}</span>
                </label>
              ))}
            </div>
          </div>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">随访间隔 (月)</label>
                <input type="number" name="followUpConfig.intervalMonths" value={formData.followUpConfig?.intervalMonths} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">最近随访时间</label>
                <input type="date" name="followUpConfig.lastFollowUpDate" value={formData.followUpConfig?.lastFollowUpDate} onChange={handleInputChange} className="w-full px-3 py-2 border rounded-lg" />
              </div>
            </div>
            <div className="p-4 bg-green-100 rounded-lg flex items-center justify-between border-l-4 border-green-500">
              <span className="text-green-800 font-medium">下次随访提示日期</span>
              <span className="text-green-900 font-bold text-lg">{formData.followUpConfig?.nextFollowUpDate || '待自动计算'}</span>
            </div>
          </div>
        </div>
      </section>

      <div className="flex gap-4 pt-4">
        <button type="submit" className="flex-1 bg-green-600 text-white font-bold py-3 rounded-xl hover:bg-green-700 shadow-lg transition active:scale-95">
          保存病人信息
        </button>
        <button type="button" onClick={onCancel} className="px-8 py-3 bg-gray-200 text-gray-700 font-bold rounded-xl hover:bg-gray-300 transition">
          取消
        </button>
      </div>
    </form>
  );
};

export default PatientForm;

import React from 'react';
import { Patient, FollowUpReminder } from '../types';

interface DashboardProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddClick: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ patients, onSelectPatient, onAddClick }) => {
  const getReminders = (): FollowUpReminder[] => {
    const today = new Date();
    return patients
      .map(p => {
        const nextDate = new Date(p.followUpConfig.nextFollowUpDate);
        const diffTime = nextDate.getTime() - today.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        return {
          patientId: p.id,
          patientName: p.name,
          daysRemaining: diffDays,
          isOverdue: diffDays < 0,
          dueDate: p.followUpConfig.nextFollowUpDate
        };
      })
      .filter(r => r.daysRemaining <= 14) // 提前14天开始提醒
      .sort((a, b) => a.daysRemaining - b.daysRemaining);
  };

  const reminders = getReminders();

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fade-in">
      {/* 随访提醒模块 */}
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-xl font-bold text-gray-800 flex items-center">
              <svg className="w-6 h-6 mr-2 text-yellow-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
              随访提醒模块
            </h2>
            <span className="bg-yellow-100 text-yellow-800 text-xs font-bold px-2 py-1 rounded-full">{reminders.length} 项待处理</span>
          </div>

          {reminders.length > 0 ? (
            <div className="space-y-3">
              {reminders.map((reminder) => (
                <div 
                  key={reminder.patientId}
                  onClick={() => {
                    const patient = patients.find(p => p.id === reminder.patientId);
                    if (patient) onSelectPatient(patient);
                  }}
                  className={`flex items-center justify-between p-4 rounded-xl border cursor-pointer transition transform hover:scale-[1.01] ${
                    reminder.isOverdue 
                      ? 'bg-red-50 border-red-100 hover:border-red-300' 
                      : 'bg-yellow-50 border-yellow-100 hover:border-yellow-300'
                  }`}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${reminder.isOverdue ? 'bg-red-500 text-white' : 'bg-yellow-500 text-white'}`}>
                      {reminder.patientName[0]}
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-900">{reminder.patientName}</h4>
                      <p className="text-sm text-gray-500">计划随访日期: {reminder.dueDate}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    {reminder.isOverdue ? (
                      <span className="text-red-600 font-bold flex items-center">
                        逾期 {Math.abs(reminder.daysRemaining)} 天
                        <svg className="w-4 h-4 ml-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6"></path></svg>
                      </span>
                    ) : (
                      <span className="text-yellow-700 font-bold flex items-center">
                        {reminder.daysRemaining === 0 ? '今日到访' : `${reminder.daysRemaining} 天后`}
                        <svg className="w-4 h-4 ml-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6"></path></svg>
                      </span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-10 bg-gray-50 rounded-xl border border-dashed">
              <p className="text-gray-400">近14天无待随访患者</p>
            </div>
          )}
        </div>
      </div>

      {/* 快捷操作与数据概览 */}
      <div className="space-y-6">
        <div className="bg-gradient-to-br from-green-600 to-green-700 p-6 rounded-2xl shadow-lg text-white">
          <h3 className="text-lg font-semibold mb-4">系统快捷操作</h3>
          <button 
            onClick={onAddClick}
            className="w-full bg-white text-green-700 font-bold py-3 px-4 rounded-xl flex items-center justify-center gap-2 hover:bg-green-50 transition active:scale-95"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6"></path></svg>
            录入新病人
          </button>
          <div className="mt-6 pt-6 border-t border-green-500/30">
            <p className="text-green-100 text-sm mb-1">已登记患者总数</p>
            <p className="text-3xl font-bold">{patients.length} 位</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">管理小贴士</h3>
          <div className="space-y-3">
            <div className="flex gap-3 text-sm">
              <span className="text-green-500 font-bold">●</span>
              <p className="text-gray-600">根据 ILAE 指南，新诊患者建议每 1-3 个月随访一次。</p>
            </div>
            <div className="flex gap-3 text-sm">
              <span className="text-green-500 font-bold">●</span>
              <p className="text-gray-600">长期服药患者需定期监测血常规及肝肾功能。</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Patient, Gender } from '../types';

interface PatientListProps {
  patients: Patient[];
  onSelect: (patient: Patient) => void;
  onDelete: (id: string) => void;
}

const PatientList: React.FC<PatientListProps> = ({ patients, onSelect, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.idCard.includes(searchTerm) ||
    p.phone.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white p-4 rounded-xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold text-gray-800">查询病人信息</h2>
        <div className="relative w-full md:w-96">
          <input 
            type="text" 
            placeholder="搜索姓名、身份证或电话..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-green-500 outline-none transition"
          />
          <svg className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredPatients.map(patient => (
          <div 
            key={patient.id} 
            className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition group relative overflow-hidden"
          >
            <div className={`absolute top-0 right-0 w-2 h-full ${patient.gender === Gender.MALE ? 'bg-blue-400' : 'bg-pink-400'}`}></div>
            <div className="flex justify-between items-start mb-4">
              <div>
