import React, { useState } from 'react';
import { Patient, Gender } from '../types';

interface PatientListProps {
  patients: Patient[];
  onSelect: (patient: Patient) => void;
  onDelete: (id: string) => void;
}

const PatientList: React.FC<PatientListProps> = ({ patients, onSelect, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.idCard.includes(searchTerm) ||
    p.phone.includes(searchTerm)
  );

  const handleExportCSV = () => {
    if (filteredPatients.length === 0) {
      alert('没有可导出的数据');
      return;
    }

    // 定义 CSV 头部
    const headers = ['姓名', '性别', '年龄', '身份证号', '联系电话', '临床诊断', '当前用药', '下次随访日期'];

    // 生成 CSV 内容
    const csvRows = filteredPatients.map(p => [
      p.name,
      p.gender,
      p.age,
      `'${p.idCard}`, // 加单引号防止Excel科学计数法
      `'${p.phone}`,
      p.diagnosis.replace(/,/g, '，'), // 替换逗号防止格式错乱
      p.medications.map(m => `${m.name}(${m.dosage})`).join('; ').replace(/,/g, '，'),
      p.followUpConfig.nextFollowUpDate
    ]);

    // 合并头部和行数据，使用逗号分隔
    const csvString = [headers, ...csvRows].map(row => row.join(',')).join('\n');

    // 添加 BOM (\uFEFF) 以确保 Excel 正确识别 UTF-8 编码（防止中文乱码）
    const blob = new Blob(['\uFEFF' + csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    // 创建隐藏的下载链接并触发
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `LZRYEK_病人随访清单_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* 搜索与导出栏 */}
      <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white p-4 rounded-xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold text-gray-800 flex items-center">
          <svg className="w-6 h-6 mr-2 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path>
          </svg>
          病人总览
        </h2>

        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto items-center">
          <div className="relative w-full sm:w-80">
            <input 
              type="text" 
              placeholder="搜索姓名、身份证或电话..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-green-500 outline-none transition"
            />
            <svg className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path>
            </svg>
          </div>

          <button 
            onClick={handleExportCSV}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-white border border-green-600 text-green-600 rounded-lg font-medium hover:bg-green-50 transition active:scale-95 whitespace-nowrap"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path>
            </svg>
            导出 CSV
          </button>
        </div>
      </div>

      {/* 数据表格 */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 border-b border-gray-100">
                <th className="px-6 py-4 text-sm font-semibold text-gray-600">姓名</th>
                <th className="px-6 py-4 text-sm font-semibold text-gray-600">基本信息</th>
