import React, { useState } from 'react';
import { Patient, Gender } from '../types';

interface PatientListProps {
  patients: Patient[];
  onSelect: (patient: Patient) => void;
  onDelete: (id: string) => void;
}

const PatientList: React.FC<PatientListProps> = ({ patients, onSelect, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.idCard.includes(searchTerm) ||
    p.phone.includes(searchTerm)
  );

  const handleExportCSV = () => {
    if (filteredPatients.length === 0) {
      alert('没有可导出的数据');
      return;
    }
    const headers = ['姓名', '性别', '年龄', '身份证号', '联系电话', '临床诊断', '当前用药', '下次随访日期'];
    const csvRows = filteredPatients.map(p => [
      p.name, p.gender, p.age, `'${p.idCard}`, `'${p.phone}`,
      p.diagnosis.replace(/,/g, '，'),
      p.medications.map(m => `${m.name}(${m.dosage})`).join('; ').replace(/,/g, '，'),
      p.followUpConfig.nextFollowUpDate
    ]);
    const csvString = [headers, ...csvRows].map(row => row.join(',')).join('\n');
    const blob = new Blob(['\uFEFF' + csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `LZRYEK_随访清单_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

