              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 bg-white/40 border-0 rounded-2xl focus:ring-4 focus:ring-green-500/20 focus:bg-white/80 outline-none transition-all duration-300"
            />
            <svg className="w-5 h-5 text-gray-400 absolute left-4 top-3.5 group-focus-within:text-green-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path>
            </svg>
          </div>

          <button 
            onClick={handleExportCSV}
            className="flex items-center justify-center gap-2 px-6 py-3 bg-white/50 border border-white/50 text-gray-700 rounded-2xl font-bold hover:bg-white shadow-sm transition active:scale-95 whitespace-nowrap"
          >
            <svg className="w-5 h-5 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
            导出清单
          </button>
        </div>
      </div>

      {/* iOS 列表风格数据表格 */}
      <div className="glass rounded-[2rem] overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/30 border-b border-white/20">
                <th className="px-8 py-5 text-sm font-bold text-gray-400 uppercase tracking-wider">姓名与基础</th>
