import React, { useState, useEffect } from 'react';
import { Patient, Gender, Medication } from '../types';
import { COMMON_MEDICATIONS, FOLLOW_UP_ITEMS } from '../constants';

interface PatientFormProps {
  initialData?: Patient;
  onSubmit: (data: Patient) => void;
  onCancel: () => void;
}

const PatientForm: React.FC<PatientFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '',
    gender: Gender.MALE,
    age: 0,
    idCard: '',
    phone: '',
    clinicalSummary: { seizureType: '', eeg: '', mri: '', genetic: '', other: '' },
    diagnosis: '',
    diagnosisDate: new Date().toISOString().split('T')[0],
    medications: [{ name: '', dosage: '' }],
    followUpConfig: { items: [], intervalMonths: 3, lastFollowUpDate: new Date().toISOString().split('T')[0], nextFollowUpDate: '' }
  });

  useEffect(() => { if (initialData) setFormData(initialData); }, [initialData]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({ ...prev, [parent]: { ...(prev[parent as keyof Patient] as any), [child]: value } }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleMedicationChange = (index: number, field: keyof Medication, value: string) => {
    const newMeds = [...(formData.medications || [])];
    newMeds[index] = { ...newMeds[index], [field]: value };
    setFormData(prev => ({ ...prev, medications: newMeds }));
  };

  const calculateNextDate = () => {
    if (!formData.followUpConfig?.lastFollowUpDate || !formData.followUpConfig?.intervalMonths) return;
    const lastDate = new Date(formData.followUpConfig.lastFollowUpDate);
    lastDate.setMonth(lastDate.getMonth() + Number(formData.followUpConfig.intervalMonths));
    setFormData(prev => ({ ...prev, followUpConfig: { ...prev.followUpConfig!, nextFollowUpDate: lastDate.toISOString().split('T')[0] } }));
  };

  useEffect(() => { calculateNextDate(); }, [formData.followUpConfig?.lastFollowUpDate, formData.followUpConfig?.intervalMonths]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({ ...(formData as Patient), id: initialData?.id || crypto.randomUUID(), createdAt: initialData?.createdAt || Date.now() });
  };

  const toggleItem = (item: string) => {
    const items = formData.followUpConfig?.items || [];
    setFormData(prev => ({ ...prev, followUpConfig: { ...prev.followUpConfig!, items: items.includes(item) ? items.filter(i => i !== item) : [...items, item] } }));
  };

  return (
    <form onSubmit={handleSubmit} className="glass rounded-[2.5rem] p-8 space-y-10 animate-fade-in overflow-y-auto max-h-[85vh] shadow-2xl">
      <div className="flex justify-between items-center pb-6 border-b border-white/30">
        <div>
           <h2 className="text-3xl font-black text-gray-900 tracking-tight">{initialData ? '更新患者档案' : '录入新病例'}</h2>
           <p className="text-gray-500 text-sm font-medium mt-1">请填写下方详细的临床数据</p>
        </div>
        <button type="button" onClick={onCancel} className="p-3 bg-black/5 hover:bg-black/10 rounded-full transition-colors">
          <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
      </div>

      {/* iOS 风格分段设置样式 */}
      <div className="space-y-12">
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-blue-500 rounded-full"></div>
             <h3 className="text-lg font-bold text-gray-900">核心身份信息</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 bg-white/40 p-6 rounded-[2rem] border border-white/50 shadow-inner">
            <div className="space-y-1.5">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest px-1">患者姓名</label>
              <input name="name" value={formData.name} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-blue-500/20 outline-none transition-all font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest px-1">生理性别</label>
              <select name="gender" value={formData.gender} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold">
                <option value={Gender.MALE}>男 (Male)</option>
                <option value={Gender.FEMALE}>女 (Female)</option>
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest px-1">实际年龄</label>
              <input type="number" name="age" value={formData.age} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold" required />
            </div>
          </div>
        </section>

        <section className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="glass-dark p-8 rounded-[2rem] border-0">
             <h3 className="text-lg font-bold text-gray-900 mb-6 flex items-center gap-2">
                临床概况
             </h3>
             <div className="space-y-6">
                <div className="space-y-1.5">
                  <label className="text-xs font-black text-gray-400 uppercase tracking-widest">确诊诊断</label>
                  <input name="diagnosis" value={formData.diagnosis} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/60 border-2 border-green-500 rounded-2xl shadow-sm outline-none font-bold text-lg text-green-700" placeholder="临床诊断名称" required />
                </div>
                <div className="space-y-1.5">
                  <label className="text-xs font-black text-gray-400 uppercase tracking-widest">发作形式</label>
                  <textarea name="clinicalSummary.seizureType" value={formData.clinicalSummary?.seizureType} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/60 rounded-2xl outline-none min-h-[100px]" placeholder="详细记录发作形式..." />
                </div>
             </div>
          </div>

          <div className="glass-dark p-8 rounded-[2rem] border-0">
             <h3 className="text-lg font-bold text-gray-900 mb-6">药物管理</h3>
             <div className="space-y-4">
                {(formData.medications || []).map((med, idx) => (
                  <div key={idx} className="flex gap-3 items-end group">
                    <div className="flex-1 space-y-1.5">
                      <input list="meds" value={med.name} onChange={(e) => handleMedicationChange(idx, 'name', e.target.value)} className="w-full px-4 py-3 bg-white/80 rounded-xl outline-none text-sm font-semibold" placeholder="药物名称" />
                      <datalist id="meds">{COMMON_MEDICATIONS.map(m => <option key={m} value={m}/>)}</datalist>
                    </div>
                    <div className="flex-1 space-y-1.5">
                      <input value={med.dosage} onChange={(e) => handleMedicationChange(idx, 'dosage', e.target.value)} className="w-full px-4 py-3 bg-white/80 rounded-xl outline-none text-sm" placeholder="剂量: 500mg bid" />
                    </div>
                    <button type="button" onClick={() => setFormData(p => ({ ...p, medications: p.medications?.filter((_, i) => i !== idx) }))} className="p-3 bg-red-50 text-red-500 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg></button>
                  </div>
                ))}
                <button type="button" onClick={() => setFormData(p => ({ ...p, medications: [...(p.medications || []), { name: '', dosage: '' }] }))} className="w-full py-3 bg-green-500/10 text-green-600 font-bold rounded-2xl hover:bg-green-500/20 transition-all text-sm">+ 添加联合用药</button>
             </div>
          </div>
        </section>

        <section className="bg-white/50 p-8 rounded-[2rem]">
           <h3 className="text-xl font-bold text-gray-900 mb-8">随访策略设置</h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="grid grid-cols-2 gap-3">
                 {FOLLOW_UP_ITEMS.map(item => (
                   <div key={item} onClick={() => toggleItem(item)} className={`p-4 rounded-2xl border-2 transition-all cursor-pointer flex items-center justify-center text-center text-xs font-bold leading-tight ${formData.followUpConfig?.items.includes(item) ? 'bg-indigo-500 border-indigo-500 text-white shadow-lg' : 'bg-white border-black/5 text-gray-500 hover:border-indigo-200'}`}>
                     {item}
                   </div>
                 ))}
              </div>
              <div className="space-y-8">
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">间隔 (月)</label>
                       <input type="number" name="followUpConfig.intervalMonths" value={formData.followUpConfig?.intervalMonths} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl outline-none font-bold shadow-sm" />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">末次随访</label>
                       <input type="date" name="followUpConfig.lastFollowUpDate" value={formData.followUpConfig?.lastFollowUpDate} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl outline-none font-bold shadow-sm text-sm" />
                    </div>
                 </div>
                 <div className="p-6 bg-gradient-to-r from-green-500 to-emerald-600 rounded-3xl text-white shadow-xl relative overflow-hidden">
                    <div className="relative z-10 flex items-center justify-between">
                       <span className="font-bold text-green-100">智能计算下次随访日期</span>
                       <span className="text-2xl font-black">{formData.followUpConfig?.nextFollowUpDate || '计算中...'}</span>
                    </div>
                    <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-2xl -mr-10 -mt-10"></div>
                 </div>
              </div>
           </div>
        </section>
      </div>

      <div className="flex gap-6 pt-10 sticky bottom-0 bg-white/10 backdrop-blur-sm -mx-8 px-8 pb-4">
        <button type="submit" className="flex-1 bg-indigo-600 text-white font-black py-5 rounded-[1.5rem] shadow-2xl hover:bg-indigo-700 transition-all active:scale-[0.98] text-lg">
          确认存档
        </button>
        <button type="button" onClick={onCancel} className="px-10 py-5 bg-white/80 text-gray-700 font-bold rounded-[1.5rem] hover:bg-white shadow-sm transition-all text-lg">
          暂不保存
        </button>
      </div>
    </form>
  );
};

