import React, { useState, useEffect } from 'react';
import Dashboard from './components/Dashboard';
import PatientForm from './components/PatientForm';
import PatientList from './components/PatientList';
import AssessmentTool from './components/AssessmentTool';
import { storage } from './services/storage';
import { Patient } from './types';

enum View {
  DASHBOARD = 'DASHBOARD',
  LIST = 'LIST',
  FORM = 'FORM',
  ASSESSMENT = 'ASSESSMENT'
}

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.DASHBOARD);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [editingPatient, setEditingPatient] = useState<Patient | undefined>(undefined);

  useEffect(() => {
    setPatients(storage.getPatients());
  }, []);

  const handleSavePatient = (patient: Patient) => {
    if (editingPatient) {
      storage.updatePatient(patient);
    } else {
      storage.addPatient(patient);
    }
    setPatients(storage.getPatients());
    setActiveView(View.DASHBOARD);
    setEditingPatient(undefined);
  };

  const handleDeletePatient = (id: string) => {
    if (window.confirm('确认删除该病人记录？')) {
      storage.deletePatient(id);
      setPatients(storage.getPatients());
    }
  };

  const handleEditPatient = (patient: Patient) => {
    setEditingPatient(patient);
    setActiveView(View.FORM);
  };

  return (
    <div className="min-h-screen flex flex-col pb-20 md:pb-0">
      <header className="sticky top-0 z-50 glass border-b-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center gap-3">
              <div className="w-12 h-12 bg-gradient-to-br from-green-400 to-green-600 rounded-2xl flex items-center justify-center text-white font-black italic shadow-lg">
                LZ
              </div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight hidden sm:block">LZRYEK 癫痫随访</h1>
            </div>

            <nav className="flex space-x-1.5 bg-black/5 p-1.5 rounded-2xl">
              {[
                { id: View.DASHBOARD, label: '概览', icon: 'M4 6h16M4 12h16M4 18h16' },
                { id: View.LIST, label: '查询', icon: 'M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z' },
                { id: View.ASSESSMENT, label: '评估', icon: 'M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z' },
                { id: View.FORM, label: '录入', icon: 'M12 4v16m8-8H4' },
              ].map(item => (
                <button
                  key={item.id}
                  onClick={() => {
                    setActiveView(item.id);
                    if (item.id !== View.FORM) setEditingPatient(undefined);
                  }}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 ${
                    activeView === item.id 
                    ? 'bg-white shadow-sm text-green-600' 
                    : 'text-gray-500 hover:text-gray-900'
                  }`}
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path>
                  </svg>
                  <span className="hidden md:inline">{item.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        {activeView === View.DASHBOARD && (
          <Dashboard 
            patients={patients} 
            onSelectPatient={handleEditPatient} 
            onAddClick={() => setActiveView(View.FORM)}
            onAssessmentClick={() => setActiveView(View.ASSESSMENT)}
          />
        )}

        {activeView === View.LIST && (
          <PatientList 
            patients={patients} 
            onSelect={handleEditPatient} 
            onDelete={handleDeletePatient} 
          />
        )}

        {activeView === View.ASSESSMENT && (
          <AssessmentTool 
            patients={patients}
            onSaved={() => {
              setPatients(storage.getPatients());
              setActiveView(View.DASHBOARD);
            }}
          />
        )}

        {activeView === View.FORM && (
          <PatientForm 
            initialData={editingPatient}
            onSubmit={handleSavePatient}
            onCancel={() => {
              setActiveView(View.DASHBOARD);
              setEditingPatient(undefined);
            }}
          />
        )}
      </main>

      <footer className="mt-auto py-8 text-center text-gray-600 text-xs px-4">
        <p className="opacity-75">© 2024 LZRYEK Epilepsy Management. iOS Optimized Interface.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Patient, AssessmentRecord } from '../types';
import { storage } from '../services/storage';

interface AssessmentToolProps {
  patients: Patient[];
  onSaved: () => void;
}

const AssessmentTool: React.FC<AssessmentToolProps> = ({ patients, onSaved }) => {
  const [selectedPatientId, setSelectedPatientId] = useState<string>('');
  const [scores, setScores] = useState({
    emotional: 5,
    social: 5,
    seizure: 5,
    sideEffect: 5,
    overall: 5
  });
  const [notes, setNotes] = useState('');

  const handleSliderChange = (key: keyof typeof scores, val: string) => {
    setScores(prev => ({ ...prev, [key]: parseInt(val) }));
  };

  const calculateTotal = () => {
    const sum = scores.emotional + scores.social + scores.seizure + (10 - scores.sideEffect) + scores.overall;
    return (sum / 50) * 100;
  };

  const handleSave = () => {
    if (!selectedPatientId) return alert('请先选择病人');
    const patient = patients.find(p => p.id === selectedPatientId);
    if (!patient) return;

    const newRecord: AssessmentRecord = {
      id: crypto.randomUUID(),
      date: new Date().toISOString().split('T')[0],
      scores: { ...scores },
      totalScore: Math.round(calculateTotal()),
      notes
    };

    const updatedPatient = {
      ...patient,
      assessmentHistory: [...(patient.assessmentHistory || []), newRecord]
    };

    storage.updatePatient(updatedPatient);
    onSaved();
  };

  const getAdvice = (score: number) => {
    if (score >= 80) return { text: '生活质量优良', color: 'text-green-600', bg: 'bg-green-50' };
    if (score >= 60) return { text: '生活质量一般', color: 'text-blue-600', bg: 'bg-blue-50' };
    return { text: '生活质量较差，需重点关注', color: 'text-red-600', bg: 'bg-red-50' };
  };

  const currentScore = calculateTotal();
  const advice = getAdvice(currentScore);

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      <div className="glass rounded-[2.5rem] p-8 shadow-2xl">
        <h2 className="text-3xl font-black text-gray-900 mb-8 flex items-center gap-3">
           <div className="w-12 h-12 bg-indigo-500 rounded-2xl flex items-center justify-center text-white">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"></path></svg>
           </div>
           QOLIE 生活质量评估
        </h2>

        <div className="space-y-10">
          {/* 病人选择 */}
          <div className="space-y-3">
             <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">受试患者</label>
             <select 
               value={selectedPatientId}
               onChange={(e) => setSelectedPatientId(e.target.value)}
               className="w-full px-6 py-4 bg-white/60 border-0 rounded-2xl focus:ring-4 focus:ring-indigo-500/20 outline-none font-bold text-gray-800 appearance-none"
             >
               <option value="">点击选择待评估患者...</option>
               {patients.map(p => (
                 <option key={p.id} value={p.id}>{p.name} ({p.gender} | {p.age}岁)</option>
               ))}
             </select>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
            {/* 评分项 */}
            <div className="space-y-8">
               {[
                 { key: 'emotional', label: '情绪状态', desc: '焦虑、沮丧或易怒程度', color: 'accent-blue-500' },
                 { key: 'social', label: '社会功能', desc: '工作、社交及家庭生活影响', color: 'accent-purple-500' },
                 { key: 'seizure', label: '发作担忧', desc: '对下次发作的恐惧程度', color: 'accent-pink-500' },
                 { key: 'sideEffect', label: '药物副作用', desc: '乏力、头晕或认知干扰', color: 'accent-orange-500' },
                 { key: 'overall', label: '整体满意度', desc: '您对自己目前生活水平的评价', color: 'accent-green-500' },
               ].map((item) => (
                 <div key={item.key} className="space-y-3">
                   <div className="flex justify-between items-end">
                      <div>
                        <h4 className="font-bold text-gray-800">{item.label}</h4>
                        <p className="text-[10px] text-gray-400 font-medium">{item.desc}</p>
                      </div>
                      <span className="text-xl font-black text-indigo-600">{scores[item.key as keyof typeof scores]}</span>
                   </div>
                   <input 
                     type="range" 
                     min="0" max="10" 
                     value={scores[item.key as keyof typeof scores]}
                     onChange={(e) => handleSliderChange(item.key as keyof typeof scores, e.target.value)}
                     className={`w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer ${item.color}`}
                   />
                 </div>
               ))}
            </div>

            {/* 结果展示 */}
            <div className="flex flex-col items-center justify-center space-y-8 bg-white/40 rounded-[2rem] p-8 border border-white/50 shadow-inner">
               <div className="relative flex items-center justify-center">
                  <svg className="w-48 h-48 transform -rotate-90">
                    <circle cx="96" cy="96" r="80" stroke="currentColor" strokeWidth="16" fill="transparent" className="text-gray-100" />
                    <circle cx="96" cy="96" r="80" stroke="currentColor" strokeWidth="16" fill="transparent" 
                      strokeDasharray={2 * Math.PI * 80}
                      strokeDashoffset={2 * Math.PI * 80 * (1 - currentScore / 100)}
                      className="text-indigo-500 transition-all duration-1000 ease-out"
                    />
                  </svg>
                  <div className="absolute flex flex-col items-center">
                     <span className="text-5xl font-black tracking-tighter text-gray-900">{Math.round(currentScore)}</span>
                     <span className="text-xs font-bold text-gray-400 uppercase">综合得分</span>
                  </div>
               </div>

               <div className={`w-full p-6 rounded-2xl text-center transition-colors ${advice.bg}`}>
                  <h5 className={`font-black text-lg ${advice.color}`}>{advice.text}</h5>
                  <p className="text-xs text-gray-500 mt-1 font-medium italic">基于简化版 QOLIE-31 评分算法</p>
               </div>

               <div className="w-full space-y-1.5">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">评估备注 (可选)</label>
                  <textarea 
                    value={notes}
                    onChange={(e) => setNotes(e.target.value)}
                    placeholder="记录此次评估的关键观察点..."
                    className="w-full px-5 py-4 bg-white/80 rounded-2xl outline-none text-sm min-h-[100px]"
                  />
               </div>
            </div>
          </div>

          <div className="flex gap-4 pt-4">
             <button 
               onClick={handleSave}
               className="flex-1 bg-indigo-600 text-white font-black py-5 rounded-[1.5rem] shadow-xl hover:bg-indigo-700 transition-all active:scale-95 text-lg"
             >
               保存评估记录
             </button>
             <button 
               onClick={() => window.history.back()}
               className="px-8 py-5 bg-white/80 text-gray-600 font-bold rounded-[1.5rem] transition-all"
             >
               取消
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AssessmentTool;

import React from 'react';
import { Patient, FollowUpReminder } from '../types';

interface DashboardProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddClick: () => void;
  onAssessmentClick: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ patients, onSelectPatient, onAddClick, onAssessmentClick }) => {
  const getReminders = (): FollowUpReminder[] => {
    const today = new Date();
    return patients
      .map(p => {
        const nextDate = new Date(p.followUpConfig.nextFollowUpDate);
        const diffTime = nextDate.getTime() - today.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        return {
          patientId: p.id,
          patientName: p.name,
          daysRemaining: diffDays,
          isOverdue: diffDays < 0,
          dueDate: p.followUpConfig.nextFollowUpDate
        };
      })
      .filter(r => r.daysRemaining <= 14) 
      .sort((a, b) => a.daysRemaining - b.daysRemaining);
  };

  const reminders = getReminders();

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fade-in">
      <div className="lg:col-span-2 space-y-8">
        <div className="glass rounded-[2rem] p-8 overflow-hidden">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h2 className="text-2xl font-bold text-gray-900 tracking-tight">随访任务清单</h2>
              <p className="text-gray-500 text-sm mt-1">未来 14 天内需要处理的随访</p>
            </div>
            <span className="bg-white/50 backdrop-blur-sm text-gray-700 text-xs font-bold px-4 py-1.5 rounded-full border border-white/50">{reminders.length} 个任务</span>
          </div>

          {reminders.length > 0 ? (
            <div className="space-y-4">
              {reminders.map((reminder) => (
                <div 
                  key={reminder.patientId}
                  onClick={() => {
                    const patient = patients.find(p => p.id === reminder.patientId);
                    if (patient) onSelectPatient(patient);
                  }}
                  className={`flex items-center justify-between p-5 rounded-2xl transition-all active:scale-[0.98] cursor-pointer group glass-dark border-0 hover:bg-white/60`}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold shadow-sm ${reminder.isOverdue ? 'bg-red-500 text-white' : 'bg-orange-400 text-white'}`}>
                      {reminder.patientName[0]}
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-900 text-lg">{reminder.patientName}</h4>
                      <p className="text-xs text-gray-500 font-medium">随访日期: {reminder.dueDate}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    {reminder.isOverdue ? (
                      <span className="text-red-600 font-bold bg-red-100 px-3 py-1 rounded-full text-xs">
                        已逾期 {Math.abs(reminder.daysRemaining)} 天
                      </span>
                    ) : (
                      <span className="text-orange-700 font-bold bg-orange-100 px-3 py-1 rounded-full text-xs">
                        {reminder.daysRemaining === 0 ? '就在今天' : `${reminder.daysRemaining} 天后`}
                      </span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-16 glass-dark rounded-3xl border-0 border-dashed border-white/40">
              <div className="w-16 h-16 bg-white/50 rounded-full flex items-center justify-center mx-auto mb-4">
                 <svg className="w-8 h-8 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7"></path></svg>
              </div>
              <p className="text-gray-600 font-semibold text-lg">暂无待办</p>
              <p className="text-gray-400 text-sm">随访计划已全部跟进</p>
            </div>
          )}
        </div>

        {/* 新增：快速评估微件 */}
