              {patients.filter(p => p.assessmentHistory && p.assessmentHistory.length > 0).slice(0, 4).map(p => {
                const latest = p.assessmentHistory[p.assessmentHistory.length - 1];
                return (
                  <div key={p.id} className="glass-dark p-4 rounded-2xl flex items-center justify-between">
