            >
              新病人建档
            </button>
            <button 
              onClick={onAssessmentClick}
              className="w-full bg-indigo-400/30 backdrop-blur-md text-white font-bold py-4 px-4 rounded-2xl border border-white/20 flex items-center justify-center gap-2 hover:bg-indigo-400/40 transition-all active:scale-95"
            >
              生活质量评估
            </button>
          </div>
          <div className="mt-10 pt-6 border-t border-white/20">
            <p className="text-white/70 text-sm font-medium mb-1">系统已管理患者</p>
