            </div>
            <span className="bg-white/50 backdrop-blur-sm text-gray-700 text-xs font-bold px-4 py-1.5 rounded-full border border-white/50">{reminders.length} 个任务</span>
          </div>

          {reminders.length > 0 ? (
            <div className="space-y-4">
              {reminders.map((reminder) => (
                <div 
                  key={reminder.patientId}
                  onClick={() => {
                    const patient = patients.find(p => p.id === reminder.patientId);
                    if (patient) onSelectPatient(patient);
                  }}
                  className={`flex items-center justify-between p-5 rounded-2xl transition-all active:scale-[0.98] cursor-pointer group glass-dark border-0 hover:bg-white/60`}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold shadow-sm ${reminder.isOverdue ? 'bg-red-500 text-white' : 'bg-orange-400 text-white'}`}>
                      {reminder.patientName[0]}
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-900 text-lg">{reminder.patientName}</h4>
                      <p className="text-xs text-gray-500 font-medium">随访日期: {reminder.dueDate}</p>
