                            value={med.dosage} 
                            onChange={(e) => handleMedicationChange(idx, 'dosage', e.target.value)} 
                            className="w-full px-4 py-3 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-green-500/20" 
                            placeholder="如: 500mg bid" 
                          />
                        </div>

                        <button 
                          type="button" 
                          onClick={() => setFormData(p => ({ ...p, medications: p.medications?.filter((_, i) => i !== idx) }))} 
                          className="mt-6 p-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-100 transition-colors"
                        >
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                        </button>
                      </div>
                    </div>
                  );
                })}
                <button 
                  type="button" 
                  onClick={() => setFormData(p => ({ ...p, medications: [...(p.medications || []), { name: '', dosage: '' }] }))} 
                  className="w-full py-4 bg-green-500/10 text-green-600 font-black rounded-2xl hover:bg-green-500/20 transition-all text-sm border-2 border-dashed border-green-200"
                >
                  + 添加联合用药
                </button>
             </div>
          </div>
        </section>

        <section className="bg-white/50 p-8 rounded-[2rem]">
           <h3 className="text-xl font-bold mb-8">随访建议</h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                 {FOLLOW_UP_ITEMS.map(item => (
                   <div key={item} onClick={() => toggleItem(item)} className={`p-4 rounded-2xl border-2 transition-all cursor-pointer flex items-center justify-center text-center text-xs font-bold leading-tight ${formData.followUpConfig?.items.includes(item) ? 'bg-indigo-500 border-indigo-500 text-white shadow-lg' : 'bg-white border-black/5 text-gray-500 hover:border-indigo-200'}`}>
                     {item}
                   </div>
                 ))}
              </div>
              <div className="space-y-8">
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">间隔 (月)</label>
                       <input type="number" name="followUpConfig.intervalMonths" value={formData.followUpConfig?.intervalMonths} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl outline-none font-bold shadow-sm" />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">末次随访</label>
