import React, { useState, useMemo } from 'react';
import { Patient, Gender } from '../types';

interface PatientListProps {
  patients: Patient[];
  onSelect: (patient: Patient) => void;
  onDelete: (id: string) => void;
  onDeleteMultiple: (ids: string[]) => void;
}

const PatientList: React.FC<PatientListProps> = ({ patients, onSelect, onDelete, onDeleteMultiple }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [showInsights, setShowInsights] = useState(false);

  // 增强的过滤逻辑
  const filteredPatients = useMemo(() => {
    return patients.filter(p => {
      const matchesSearch = 
        p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        p.idCard.includes(searchTerm) ||
        p.phone.includes(searchTerm) ||
        p.diagnosis.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (p.clinicalSummary?.syndrome || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        p.medications.some(m => m.name.toLowerCase().includes(searchTerm.toLowerCase()));

      const patientDate = new Date(p.createdAt).toISOString().split('T')[0];
      const matchesStart = !startDate || patientDate >= startDate;
      const matchesEnd = !endDate || patientDate <= endDate;

      return matchesSearch && matchesStart && matchesEnd;
    });
  }, [patients, searchTerm, startDate, endDate]);

  // 计算可视化数据
  const stats = useMemo(() => {
    const total = filteredPatients.length;
    if (total === 0) return null;

    const genderCount = { male: 0, female: 0 };
    const ageGroups = { kids: 0, adults: 0, seniors: 0 };
    const medUsage: Record<string, number> = {};

    filteredPatients.forEach(p => {
      // 性别
      if (p.gender === Gender.MALE) genderCount.male++;
      else genderCount.female++;

      // 年龄
      if (p.age < 18) ageGroups.kids++;
      else if (p.age < 60) ageGroups.adults++;
      else ageGroups.seniors++;

      // 药物
      p.medications.forEach(m => {
        const name = m.name.split(' ')[0]; // 取中文名部分
        medUsage[name] = (medUsage[name] || 0) + 1;
      });
    });

    const topMeds = Object.entries(medUsage)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5);

    return { total, genderCount, ageGroups, topMeds };
  }, [filteredPatients]);

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedIds(filteredPatients.map(p => p.id));
    } else {
      setSelectedIds([]);
    }
  };

  const handleSelectOne = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return;
    onDeleteMultiple(selectedIds);
    setSelectedIds([]);
  };

  const handleExportCSV = () => {
    if (filteredPatients.length === 0) return alert('没有可导出的数据');
    const headers = ['建档日期', '姓名', '性别', '年龄', '临床诊断', '综合征', '药物', '剂量'];
    const csvRows = filteredPatients.map(p => [
      new Date(p.createdAt).toLocaleDateString(),
      p.name, p.gender, p.age, p.diagnosis, p.clinicalSummary?.syndrome || 'N/A',
      p.medications.map(m => m.name).join(';'),
      p.medications.map(m => m.dosage).join(';')
    ]);
    const csvString = [headers, ...csvRows].map(row => row.join(',')).join('\n');
    const blob = new Blob(['\uFEFF' + csvString], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `LZRYEK_分析报告_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      {/* 核心筛选栏 */}
      <div className="glass rounded-[2.5rem] p-8 shadow-xl space-y-6">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-green-500 rounded-2xl flex items-center justify-center text-white shadow-lg">
              <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
            </div>
            <div>
              <h2 className="text-2xl font-black text-gray-900 tracking-tight">智能档案检索</h2>
              <p className="text-gray-400 text-xs font-bold uppercase tracking-widest mt-0.5">Filter & Analytics</p>
            </div>
          </div>

          <div className="flex items-center bg-black/5 p-1.5 rounded-2xl">
             <button 
               onClick={() => setShowInsights(false)}
               className={`px-6 py-2 rounded-xl text-sm font-black transition-all ${!showInsights ? 'bg-white shadow-sm text-green-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
               数据表格
             </button>
             <button 
               onClick={() => setShowInsights(true)}
               className={`px-6 py-2 rounded-xl text-sm font-black transition-all ${showInsights ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
               可视化面板
             </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="relative group lg:col-span-2">
            <input 
              type="text" 
              placeholder="搜索姓名、药物、病情或证件号..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-white/50 border-0 rounded-2xl focus:ring-4 focus:ring-green-500/20 focus:bg-white outline-none transition-all font-bold text-gray-700 shadow-inner"
