      {showInsights && stats ? (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-fade-in">
          {/* 性别分布 */}
          <div className="glass rounded-[2rem] p-8 flex flex-col items-center justify-center space-y-6">
            <h3 className="text-sm font-black text-gray-400 uppercase tracking-widest">患者性别构成</h3>
            <div className="relative w-40 h-40">
               <svg className="w-full h-full transform -rotate-90">
                 <circle cx="80" cy="80" r="70" fill="transparent" stroke="#f472b6" strokeWidth="20" />
                 <circle cx="80" cy="80" r="70" fill="transparent" stroke="#60a5fa" strokeWidth="20" 
                    strokeDasharray={440}
                    strokeDashoffset={440 * (1 - stats.genderCount.male / stats.total)}
                    className="transition-all duration-1000"
                 />
               </svg>
               <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-3xl font-black text-gray-900">{Math.round((stats.genderCount.male / stats.total) * 100)}%</span>
                  <span className="text-[10px] font-bold text-gray-400 uppercase">男性比例</span>
               </div>
            </div>
            <div className="flex gap-8 w-full">
               <div className="flex-1 text-center">
                  <div className="text-blue-500 font-black text-xl">{stats.genderCount.male}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase">男性 (M)</div>
               </div>
               <div className="flex-1 text-center">
                  <div className="text-pink-500 font-black text-xl">{stats.genderCount.female}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase">女性 (F)</div>
               </div>
            </div>
          </div>

          {/* 年龄阶段分布 */}
          <div className="glass rounded-[2rem] p-8 space-y-6">
            <h3 className="text-sm font-black text-gray-400 uppercase tracking-widest">年龄阶段分析</h3>
            <div className="space-y-6">
              {[
                { label: '儿童/青少年 (<18)', count: stats.ageGroups.kids, color: 'bg-emerald-400' },
                { label: '青壮年 (18-60)', count: stats.ageGroups.adults, color: 'bg-indigo-400' },
                { label: '老年 (60+)', count: stats.ageGroups.seniors, color: 'bg-orange-400' },
              ].map((item, i) => (
                <div key={i} className="space-y-2">
                   <div className="flex justify-between text-xs font-bold">
                      <span className="text-gray-600">{item.label}</span>
                      <span className="text-gray-900">{item.count} 人</span>
                   </div>
                   <div className="w-full h-3 bg-white/40 rounded-full overflow-hidden">
                      <div 
                        className={`h-full ${item.color} transition-all duration-1000`} 
                        style={{ width: `${(item.count / stats.total) * 100}%` }}
                      ></div>
                   </div>
                </div>
              ))}
            </div>
          </div>

          {/* 常用药物排行 */}
          <div className="glass rounded-[2rem] p-8 space-y-6">
            <h3 className="text-sm font-black text-gray-400 uppercase tracking-widest">常用药物 TOP 5</h3>
            <div className="space-y-4">
               {stats.topMeds.map(([name, count], i) => (
                 <div key={i} className="flex items-center gap-4">
                    <div className="w-6 h-6 rounded-lg bg-black/5 flex items-center justify-center text-[10px] font-black text-gray-500">{i+1}</div>
                    <div className="flex-1 space-y-1">
                       <div className="flex justify-between text-xs font-bold">
                          <span className="text-gray-800">{name}</span>
                          <span className="text-indigo-600">{count} 例</span>
                       </div>
                       <div className="w-full h-1.5 bg-white/40 rounded-full">
                          <div 
                            className="h-full bg-indigo-500 rounded-full" 
                            style={{ width: `${(count / stats.total) * 100}%` }}
                          ></div>
                       </div>
                    </div>
                 </div>
               ))}
               {stats.topMeds.length === 0 && <p className="text-center text-gray-400 text-xs py-10">暂无用药统计数据</p>}
            </div>
          </div>
        </div>
      ) : (
        /* 数据表格视图 */
        <div className="glass rounded-[2.5rem] overflow-hidden shadow-2xl border-0">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white/30 border-b border-white/20">
                  <th className="px-6 py-5 w-12">
                    <div className="flex items-center justify-center">
                      <input 
                        type="checkbox" 
                        onChange={handleSelectAll}
                        checked={selectedIds.length === filteredPatients.length && filteredPatients.length > 0}
                        className="w-5 h-5 rounded-md border-gray-300 text-green-600 focus:ring-green-500 cursor-pointer"
                      />
                    </div>
                  </th>
                  <th className="px-4 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">基本档案</th>
                  <th className="px-4 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">诊断/综合征</th>
                  <th className="px-4 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">用药方案</th>
                  <th className="px-4 py-5 text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">操作</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/20">
                {filteredPatients.map((p) => {
                  const isSelected = selectedIds.includes(p.id);
                  return (
                    <tr key={p.id} className={`transition-all duration-200 ${isSelected ? 'bg-green-500/5' : 'hover:bg-white/40'}`}>
                      <td className="px-6 py-6 text-center">
                        <input 
                          type="checkbox" 
                          checked={isSelected}
                          onChange={() => handleSelectOne(p.id)}
                          className="w-5 h-5 rounded-md border-gray-300 text-green-600 focus:ring-green-500 cursor-pointer"
                        />
                      </td>
                      <td className="px-4 py-6" onClick={() => onSelect(p)}>
                        <div className="flex items-center gap-4 cursor-pointer">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-black shadow-lg ${p.gender === Gender.MALE ? 'bg-blue-400' : 'bg-pink-400'}`}>
                            {p.name[0]}
                          </div>
                          <div>
                            <div className="font-bold text-gray-900 text-lg">{p.name}</div>
                            <div className="text-[10px] font-black text-gray-400 uppercase tracking-tighter">
                               {new Date(p.createdAt).toLocaleDateString()} 建档
                            </div>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-6">
                        <div className="flex flex-col gap-1.5">
                          <span className="inline-block px-2.5 py-1 bg-green-50 text-green-700 text-xs font-black rounded-lg border border-green-100 max-w-fit">{p.diagnosis}</span>
                          {p.clinicalSummary?.syndrome && (
                            <span className="inline-block px-2.5 py-1 bg-indigo-50 text-indigo-700 text-[10px] font-black rounded-lg border border-indigo-100 max-w-fit">{p.clinicalSummary.syndrome}</span>
                          )}
                        </div>
                      </td>
                      <td className="px-4 py-6">
                        <div className="flex flex-wrap gap-1.5 max-w-[200px]">
                          {p.medications.map((m, i) => (
                            <span key={i} className="px-2 py-0.5 bg-white border border-gray-100 text-gray-700 text-[9px] font-black rounded shadow-sm">
                              {m.name.split(' ')[0]}
                            </span>
                          ))}
                        </div>
                      </td>
                      <td className="px-4 py-6">
                        <div className="flex items-center justify-center gap-2">
                           {selectedIds.length > 0 && isSelected ? (
                             <span className="text-green-600 text-[10px] font-black uppercase tracking-widest">已选中</span>
                           ) : (
                             <button onClick={() => onDelete(p.id)} className="p-3 text-red-400 hover:text-red-600 transition-colors">
                               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                             </button>
                           )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          {filteredPatients.length === 0 && (
            <div className="py-24 text-center">
               <p className="text-gray-400 font-bold text-lg">按当前筛选条件未找到匹配结果</p>
            </div>
          )}
        </div>
      )}

      {selectedIds.length > 0 && (
        <div className="fixed bottom-10 left-1/2 transform -translate-x-1/2 glass px-10 py-5 rounded-full flex items-center gap-10 shadow-2xl animate-fade-in border-green-500/20 z-50">
           <span className="text-sm font-black text-gray-900">已选中 {selectedIds.length} 位患者</span>
           <div className="flex gap-4">
              <button 
                onClick={handleBatchDelete}
                className="px-6 py-2.5 bg-red-500 text-white text-xs font-black rounded-xl shadow-lg hover:bg-red-600 transition active:scale-95"
              >
                批量删除
              </button>
              <button 
                onClick={() => setSelectedIds([])}
                className="px-6 py-2.5 bg-gray-200 text-gray-700 text-xs font-black rounded-xl hover:bg-gray-300 transition"
              >
                取消选择
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default PatientList;

import React, { useState, useMemo } from 'react';
import { Patient, Gender } from '../types';

interface PatientListProps {
  patients: Patient[];
  onSelect: (patient: Patient) => void;
  onDelete: (id: string) => void;
  onDeleteMultiple: (ids: string[]) => void;
}

const PatientList: React.FC<PatientListProps> = ({ patients, onSelect, onDelete, onDeleteMultiple }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [showInsights, setShowInsights] = useState(false);

  // 1. 增强的过滤逻辑：支持药物、病情、基本信息的多维度模糊匹配
  const filteredPatients = useMemo(() => {
    return patients.filter(p => {
      const searchLower = searchTerm.toLowerCase();
      const matchesSearch = 
        p.name.toLowerCase().includes(searchLower) || 
        p.idCard.includes(searchTerm) ||
        p.phone.includes(searchTerm) ||
        p.diagnosis.toLowerCase().includes(searchLower) ||
        (p.clinicalSummary?.syndrome || '').toLowerCase().includes(searchLower) ||
        p.medications.some(m => m.name.toLowerCase().includes(searchLower));

      const patientDate = new Date(p.createdAt).toISOString().split('T')[0];
      const matchesStart = !startDate || patientDate >= startDate;
      const matchesEnd = !endDate || patientDate <= endDate;

      return matchesSearch && matchesStart && matchesEnd;
    });
  }, [patients, searchTerm, startDate, endDate]);

  // 2. 针对儿科优化的统计逻辑
  const stats = useMemo(() => {
    const total = filteredPatients.length;
    if (total === 0) return null;

    const genderCount = { male: 0, female: 0 };
    // 细化儿科年龄分段 (参考儿科学标准)
    const ageGroups = {
      infant: 0,    // 婴儿期 (0-1岁)
      toddler: 0,   // 幼儿期 (1-3岁)
      preschool: 0, // 学龄前期 (3-6岁)
      school: 0,    // 学龄期 (6-12岁)
      adolescent: 0 // 青春期 (12-18岁+)
    };
    const medUsage: Record<string, number> = {};
    const diagnosisUsage: Record<string, number> = {};

    filteredPatients.forEach(p => {
      // 性别统计
      if (p.gender === Gender.MALE) genderCount.male++;
      else genderCount.female++;

      // 儿科年龄细化统计
      if (p.age <= 1) ageGroups.infant++;
      else if (p.age <= 3) ageGroups.toddler++;
      else if (p.age <= 6) ageGroups.preschool++;
      else if (p.age <= 12) ageGroups.school++;
      else ageGroups.adolescent++;

      // 药物热度
      p.medications.forEach(m => {
        const name = m.name.split(' ')[0].trim();
        if (name) medUsage[name] = (medUsage[name] || 0) + 1;
      });

      // 病情/诊断热度
      const diag = p.diagnosis.trim();
      if (diag) diagnosisUsage[diag] = (diagnosisUsage[diag] || 0) + 1;
    });

    const topMeds = Object.entries(medUsage).sort((a, b) => b[1] - a[1]).slice(0, 5);
    const topDiags = Object.entries(diagnosisUsage).sort((a, b) => b[1] - a[1]).slice(0, 5);

    return { total, genderCount, ageGroups, topMeds, topDiags };
  }, [filteredPatients]);

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSelectedIds(e.target.checked ? filteredPatients.map(p => p.id) : []);
  };

  const handleSelectOne = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return;
    onDeleteMultiple(selectedIds);
    setSelectedIds([]);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-24">
      {/* 高级筛选面板 */}
      <div className="glass rounded-[2.5rem] p-8 shadow-xl space-y-6 border-white/40">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 bg-indigo-500 rounded-[1.25rem] flex items-center justify-center text-white shadow-lg shadow-indigo-200">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
            </div>
            <div>
              <h2 className="text-2xl font-black text-gray-900">儿科随访智能查询</h2>
              <p className="text-indigo-500 text-[10px] font-black uppercase tracking-[0.2em] mt-0.5">Pediatric Epilepsy Database</p>
            </div>
          </div>

          <div className="flex items-center bg-gray-100/80 p-1.5 rounded-2xl border border-gray-200/50">
             <button 
               onClick={() => setShowInsights(false)}
               className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${!showInsights ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
               档案列表
             </button>
             <button 
               onClick={() => setShowInsights(true)}
               className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${showInsights ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
               分布视图
             </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-4">
          <div className="relative group lg:col-span-6">
            <input 
              type="text" 
              placeholder="搜索：患儿姓名、药物名称(如左乙拉西坦)、病情(如局灶性)..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-white/60 border-2 border-transparent rounded-2xl focus:border-indigo-500/20 focus:bg-white outline-none transition-all font-bold text-gray-700 shadow-inner"
            />
            <svg className="w-5 h-5 text-gray-400 absolute left-4 top-[1.15rem] group-focus-within:text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
          </div>

          <div className="lg:col-span-4 flex gap-2">
             <div className="flex-1 relative">
                <span className="absolute left-4 top-1 text-[8px] font-black text-indigo-400 uppercase">From</span>
                <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full pl-4 pr-2 pt-5 pb-2 bg-white/60 border-0 rounded-2xl outline-none font-bold text-xs" />
             </div>
             <div className="flex-1 relative">
                <span className="absolute left-4 top-1 text-[8px] font-black text-indigo-400 uppercase">To</span>
                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full pl-4 pr-2 pt-5 pb-2 bg-white/60 border-0 rounded-2xl outline-none font-bold text-xs" />
             </div>
          </div>

          <button onClick={() => {setSearchTerm(''); setStartDate(''); setEndDate('');}} className="lg:col-span-2 py-4 bg-white border border-gray-200 text-gray-500 rounded-2xl font-bold text-xs hover:bg-gray-50 transition active:scale-95">
            重置筛选
          </button>
        </div>
      </div>

      {showInsights && stats ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in">
          {/* 性别比例 (Donut Chart) */}
          <div className="glass rounded-[2.5rem] p-8 flex flex-col items-center justify-center space-y-6 border-white/40 shadow-xl">
            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">患儿性别分布</h3>
            <div className="relative w-44 h-44">
               <svg className="w-full h-full transform -rotate-90">
                 <circle cx="88" cy="88" r="74" fill="transparent" stroke="#f472b6" strokeWidth="18" />
                 <circle cx="88" cy="88" r="74" fill="transparent" stroke="#6366f1" strokeWidth="18" 
                    strokeDasharray={465}
                    strokeDashoffset={465 * (1 - stats.genderCount.male / stats.total)}
                    className="transition-all duration-1000 ease-out"
                 />
               </svg>
               <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-4xl font-black text-gray-900">{Math.round((stats.genderCount.male / stats.total) * 100)}%</span>
                  <span className="text-[9px] font-bold text-gray-400 uppercase tracking-tighter">男孩占比</span>
               </div>
            </div>
            <div className="flex gap-10 w-full pt-2">
               <div className="flex-1 text-center">
                  <div className="text-indigo-600 font-black text-2xl">{stats.genderCount.male}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase">男 (Boy)</div>
               </div>
               <div className="flex-1 text-center">
                  <div className="text-pink-500 font-black text-2xl">{stats.genderCount.female}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase">女 (Girl)</div>
               </div>
            </div>
          </div>

          {/* 儿科精细年龄段 (Horizontal Bar Chart) */}
          <div className="glass rounded-[2.5rem] p-8 space-y-6 border-white/40 shadow-xl">
            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">儿科年龄阶段分布</h3>
            <div className="space-y-4">
              {[
                { label: '婴儿期 (0-1岁)', count: stats.ageGroups.infant, color: 'bg-rose-400' },
                { label: '幼儿期 (1-3岁)', count: stats.ageGroups.toddler, color: 'bg-orange-400' },
                { label: '学龄前期 (3-6岁)', count: stats.ageGroups.preschool, color: 'bg-amber-400' },
                { label: '学龄期 (6-12岁)', count: stats.ageGroups.school, color: 'bg-emerald-400' },
                { label: '青春期 (12-18岁+)', count: stats.ageGroups.adolescent, color: 'bg-indigo-400' },
              ].map((item, i) => (
                <div key={i} className="space-y-1.5">
                   <div className="flex justify-between text-[10px] font-black uppercase">
                      <span className="text-gray-500">{item.label}</span>
                      <span className="text-gray-900">{item.count} 人</span>
                   </div>
                   <div className="w-full h-2.5 bg-gray-100 rounded-full overflow-hidden border border-gray-200/50">
                      <div className={`h-full ${item.color} transition-all duration-1000 ease-out`} style={{ width: `${(item.count / stats.total) * 100}%` }}></div>
                   </div>
                </div>
              ))}
            </div>
          </div>

          {/* 用药热度统计 */}
          <div className="glass rounded-[2.5rem] p-8 space-y-6 border-white/40 shadow-xl">
            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">当前筛选用药热度</h3>
            <div className="space-y-5">
               {stats.topMeds.map(([name, count], i) => (
                 <div key={i} className="flex items-center gap-4">
                    <div className="w-8 h-8 rounded-xl bg-indigo-50 flex items-center justify-center text-xs font-black text-indigo-500 border border-indigo-100">{i+1}</div>
                    <div className="flex-1 space-y-1">
                       <div className="flex justify-between items-center">
                          <span className="text-sm font-bold text-gray-800">{name}</span>
                          <span className="text-indigo-600 text-xs font-black">{count} 例</span>
                       </div>
                       <div className="w-full h-1.5 bg-gray-100 rounded-full">
                          <div className="h-full bg-indigo-400 rounded-full" style={{ width: `${(count / stats.total) * 100}%` }}></div>
                       </div>
                    </div>
                 </div>
               ))}
               {stats.topMeds.length === 0 && <div className="py-12 text-center text-gray-400 text-xs font-bold italic">无用药数据</div>}
            </div>
          </div>

          {/* 病情/诊断热度统计 */}
          <div className="glass rounded-[2.5rem] p-8 space-y-6 border-white/40 shadow-xl md:col-span-2 lg:col-span-3">
             <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">病情与诊断分布 (Top 5)</h3>
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
                {stats.topDiags.map(([name, count], i) => (
                  <div key={i} className="bg-white/50 p-5 rounded-3xl border border-white/60 text-center space-y-2 group hover:bg-white transition-all">
                     <div className="text-xs font-black text-gray-400 group-hover:text-indigo-500 transition-colors">RANK {i+1}</div>
                     <div className="text-lg font-black text-gray-900 truncate" title={name}>{name}</div>
                     <div className="text-2xl font-black text-indigo-600">{count} <span className="text-[10px] text-indigo-300">人</span></div>
                  </div>
                ))}
                {stats.topDiags.length === 0 && <div className="col-span-full py-6 text-center text-gray-400 text-sm font-bold">无诊断统计数据</div>}
             </div>
          </div>
        </div>
      ) : (
        /* 数据表格视图 */
        <div className="glass rounded-[2.5rem] overflow-hidden shadow-2xl border-white/40">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white/30 border-b border-white/20">
                  <th className="px-6 py-6 w-12">
                    <div className="flex items-center justify-center">
                      <input 
                        type="checkbox" 
                        onChange={handleSelectAll}
                        checked={selectedIds.length === filteredPatients.length && filteredPatients.length > 0}
                        className="w-5 h-5 rounded-md border-gray-300 text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                      />
                    </div>
                  </th>
                  <th className="px-4 py-6 text-[10px] font-black text-gray-400 uppercase tracking-widest">患儿信息</th>
                  <th className="px-4 py-6 text-[10px] font-black text-gray-400 uppercase tracking-widest">诊断情况</th>
                  <th className="px-4 py-6 text-[10px] font-black text-gray-400 uppercase tracking-widest">用药方案</th>
                  <th className="px-4 py-6 text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">管理</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/20">
                {filteredPatients.map((p) => {
                  const isSelected = selectedIds.includes(p.id);
                  return (
                    <tr key={p.id} className={`transition-all duration-300 ${isSelected ? 'bg-indigo-500/10' : 'hover:bg-white/40'}`}>
                      <td className="px-6 py-6 text-center">
                        <input type="checkbox" checked={isSelected} onChange={() => handleSelectOne(p.id)} className="w-5 h-5 rounded-md border-gray-300 text-indigo-600 cursor-pointer" />
                      </td>
                      <td className="px-4 py-6" onClick={() => onSelect(p)}>
                        <div className="flex items-center gap-4 cursor-pointer group">
                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-white font-black shadow-lg transition-transform group-hover:scale-110 ${p.gender === Gender.MALE ? 'bg-blue-400' : 'bg-pink-400'}`}>
                            {p.name[0]}
                          </div>
                          <div>
                            <div className="font-black text-gray-900 text-lg leading-tight">{p.name}</div>
                            <div className="text-[10px] font-black text-gray-400 mt-1 uppercase">
                               {p.gender} · {p.age} 岁
                            </div>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-6">
                        <div className="flex flex-col gap-1.5">
                          <span className="inline-block px-3 py-1 bg-white/80 text-gray-800 text-xs font-black rounded-lg border border-gray-200 max-w-fit">{p.diagnosis}</span>
                          {p.clinicalSummary?.syndrome && (
                            <span className="inline-block px-3 py-1 bg-indigo-50 text-indigo-700 text-[9px] font-black rounded-lg border border-indigo-100 max-w-fit">{p.clinicalSummary.syndrome}</span>
                          )}
                        </div>
                      </td>
                      <td className="px-4 py-6">
                        <div className="flex flex-wrap gap-1.5 max-w-[240px]">
                          {p.medications.map((m, i) => (
                            <div key={i} className="flex flex-col px-2.5 py-1.5 bg-white border border-gray-100 rounded-xl shadow-sm">
                              <span className="text-[10px] font-black text-indigo-600 leading-none">{m.name.split(' ')[0]}</span>
                              <span className="text-[8px] font-bold text-gray-400 mt-1">{m.dosage}</span>
                            </div>
                          ))}
                        </div>
                      </td>
                      <td className="px-4 py-6">
                        <div className="flex items-center justify-center gap-2">
                           <button onClick={() => onDelete(p.id)} className="p-3 bg-red-50 text-red-400 hover:bg-red-500 hover:text-white rounded-xl transition-all active:scale-90">
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                           </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          {filteredPatients.length === 0 && (
            <div className="py-32 text-center space-y-4">
               <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto opacity-50">
                  <svg className="w-10 h-10 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
               </div>
               <p className="text-gray-400 font-black text-lg">未找到符合条件的患儿档案</p>
            </div>
          )}
        </div>
      )}

      {/* 底部悬浮操作栏 */}
      {selectedIds.length > 0 && (
        <div className="fixed bottom-10 left-1/2 transform -translate-x-1/2 glass px-10 py-6 rounded-[2rem] flex items-center gap-12 shadow-2xl animate-fade-in border-indigo-500/20 z-50">
           <div>
              <span className="text-sm font-black text-gray-900">已选中 {selectedIds.length} 名患儿</span>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Batch Actions Active</p>
           </div>
           <div className="flex gap-4">
              <button 
                onClick={handleBatchDelete}
                className="px-8 py-3 bg-red-500 text-white text-xs font-black rounded-2xl shadow-lg hover:bg-red-600 transition active:scale-95"
              >
                批量移除档案
              </button>
              <button 
                onClick={() => setSelectedIds([])}
                className="px-8 py-3 bg-gray-200 text-gray-700 text-xs font-black rounded-2xl hover:bg-gray-300 transition"
              >
                取消选中
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default PatientList;

import React, { useState, useEffect } from 'react';
import { Patient, Gender, Medication } from '../types';
import { COMMON_MEDICATIONS, FOLLOW_UP_ITEMS } from '../constants';

interface PatientFormProps {
  initialData?: Patient;
  onSubmit: (data: Patient) => void;
  onCancel: () => void;
}

const PatientForm: React.FC<PatientFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '',
    gender: Gender.MALE,
    age: 0,
    idCard: '',
    phone: '',
    clinicalSummary: { 
      syndrome: '', 
      seizureType: '', 
      eeg: '', 
      mri: '', 
      genetic: '', 
      other: '' 
    },
    diagnosis: '',
    diagnosisDate: new Date().toISOString().split('T')[0],
    medications: [{ name: '', dosage: '' }],
    followUpConfig: { 
      items: [], 
      intervalMonths: 3, 
      lastFollowUpDate: new Date().toISOString().split('T')[0], 
      nextFollowUpDate: '' 
    }
  });

  useEffect(() => { if (initialData) setFormData(initialData); }, [initialData]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({ 
        ...prev, 
        [parent]: { ...(prev[parent as keyof Patient] as any), [child]: value } 
      }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleMedicationChange = (index: number, field: keyof Medication, value: string) => {
    const newMeds = [...(formData.medications || [])];
    newMeds[index] = { ...newMeds[index], [field]: value };
    setFormData(prev => ({ ...prev, medications: newMeds }));
  };

  const calculateNextDate = () => {
    if (!formData.followUpConfig?.lastFollowUpDate || !formData.followUpConfig?.intervalMonths) return;
    const lastDate = new Date(formData.followUpConfig.lastFollowUpDate);
    lastDate.setMonth(lastDate.getMonth() + Number(formData.followUpConfig.intervalMonths));
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { ...prev.followUpConfig!, nextFollowUpDate: lastDate.toISOString().split('T')[0] } 
    }));
  };

  useEffect(() => { calculateNextDate(); }, [formData.followUpConfig?.lastFollowUpDate, formData.followUpConfig?.intervalMonths]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalMeds = (formData.medications || []).map(m => ({
      ...m,
      name: m.name === ' ' ? '' : m.name
    }));
    onSubmit({ 
      ...(formData as Patient), 
      medications: finalMeds, 
      id: initialData?.id || crypto.randomUUID(), 
      createdAt: initialData?.createdAt || Date.now() 
    });
  };

  const toggleItem = (item: string) => {
    const items = formData.followUpConfig?.items || [];
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { 
        ...prev.followUpConfig!, 
        items: items.includes(item) ? items.filter(i => i !== item) : [...items, item] 
      } 
    }));
  };

  return (
    <form onSubmit={handleSubmit} className="glass rounded-[2.5rem] p-8 space-y-10 animate-fade-in overflow-y-auto max-h-[85vh] shadow-2xl text-gray-900 border-white/40">
      <div className="flex justify-between items-center pb-6 border-b border-white/30">
        <div>
           <h2 className="text-3xl font-black text-gray-900 tracking-tight">
             {initialData ? '更新患儿档案' : '儿科病例录入'}
           </h2>
           <p className="text-indigo-500 text-xs font-black uppercase tracking-[0.2em] mt-1">
             Pediatric Clinical Records
           </p>
        </div>
        <button type="button" onClick={onCancel} className="p-3 bg-black/5 hover:bg-black/10 rounded-full transition-colors">
          <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
      </div>

      <div className="space-y-12">
        {/* 核心身份信息 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-indigo-500 rounded-full"></div>
             <h3 className="text-lg font-bold">基本身份信息</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 bg-white/40 p-8 rounded-[2rem] border border-white/50 shadow-inner">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">患儿姓名</label>
              <input name="name" value={formData.name} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-indigo-500/20 outline-none transition-all font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">性别</label>
              <select name="gender" value={formData.gender} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold">
                <option value={Gender.MALE}>男 (Boy)</option>
                <option value={Gender.FEMALE}>女 (Girl)</option>
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">当前年龄</label>
              <input type="number" name="age" value={formData.age} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold" required />
            </div>
          </div>
        </section>

        {/* 临床概况 - 核心医学数据 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-emerald-500 rounded-full"></div>
             <h3 className="text-lg font-bold">临床概况与医学检查</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">临床诊断</label>
                <input name="diagnosis" value={formData.diagnosis} onChange={handleInputChange} className="w-full px-6 py-5 bg-white/80 border-2 border-emerald-500/30 rounded-2xl shadow-sm outline-none font-black text-lg text-emerald-700 placeholder:text-emerald-200" placeholder="如: 局灶性癫痫" required />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">癫痫综合征</label>
                <input name="clinicalSummary.syndrome" value={formData.clinicalSummary?.syndrome} onChange={handleInputChange} className="w-full px-6 py-5 bg-white/80 border-2 border-indigo-500/30 rounded-2xl shadow-sm outline-none font-black text-lg text-indigo-700 placeholder:text-indigo-200" placeholder="如: West 综合征" />
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">发作形式特征</label>
              <textarea name="clinicalSummary.seizureType" value={formData.clinicalSummary?.seizureType} onChange={handleInputChange} className="w-full px-6 py-4 bg-white/60 rounded-2xl outline-none min-h-[80px] text-sm font-medium" placeholder="描述患儿发作的具体动作、持续时间、伴随症状等..." />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-1">
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                  脑电图 (EEG)
                </label>
                <textarea name="clinicalSummary.eeg" value={formData.clinicalSummary?.eeg} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px] focus:ring-2 focus:ring-indigo-400/50" placeholder="描述高峰失律、棘慢波分布等..." />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-1">
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                  头颅 MRI/影像
                </label>
                <textarea name="clinicalSummary.mri" value={formData.clinicalSummary?.mri} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px] focus:ring-2 focus:ring-indigo-400/50" placeholder="皮层发育畸形、海马硬化等..." />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-1">
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                  基因/代谢筛选
                </label>
                <textarea name="clinicalSummary.genetic" value={formData.clinicalSummary?.genetic} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px] focus:ring-2 focus:ring-indigo-400/50" placeholder="SCN1A、KCNQ2 等基因突变结果..." />
              </div>
            </div>
          </div>
        </section>

        {/* 药物管理 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-purple-500 rounded-full"></div>
             <h3 className="text-lg font-bold">治疗与药物方案</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0">
             <div className="space-y-6">
                {(formData.medications || []).map((med, idx) => {
                  const isKnown = COMMON_MEDICATIONS.includes(med.name);
                  const showManualInput = !isKnown && med.name !== '';

                  return (
                    <div key={idx} className="bg-white/50 p-6 rounded-3xl border border-white/50 space-y-4 group relative shadow-sm">
                      <div className="flex gap-4 items-start">
                        <div className="flex-1 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">抗癫痫药物 (ASM)</label>
                          <select 
                            value={isKnown ? med.name : (med.name === '' ? '' : 'OTHER')}
                            onChange={(e) => {
                              const val = e.target.value;
                              if (val === 'OTHER') handleMedicationChange(idx, 'name', ' '); 
                              else handleMedicationChange(idx, 'name', val);
                            }}
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-bold border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-indigo-500/20"
                          >
                            <option value="">选择药物...</option>
                            {COMMON_MEDICATIONS.map(m => <option key={m} value={m}>{m}</option>)}
                            <option value="OTHER">其他 (手动输入)...</option>
                          </select>

                          {showManualInput && (
                            <input 
                              autoFocus
                              value={med.name === ' ' ? '' : med.name}
                              onChange={(e) => handleMedicationChange(idx, 'name', e.target.value)}
                              className="w-full px-4 py-4 mt-2 bg-indigo-50/50 border-2 border-indigo-200 rounded-xl outline-none text-sm font-black text-indigo-700 animate-fade-in"
                              placeholder="输入未在列表中的药物名称"
                            />
                          )}
                        </div>

                        <div className="flex-1 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">用法用量</label>
                          <input 
                            value={med.dosage} 
                            onChange={(e) => handleMedicationChange(idx, 'dosage', e.target.value)} 
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-purple-500/20" 
                            placeholder="如: 0.25g bid" 
                          />
                        </div>

                        <button 
                          type="button" 
                          onClick={() => setFormData(p => ({ ...p, medications: p.medications?.filter((_, i) => i !== idx) }))} 
                          className="mt-6 p-4 bg-red-50 text-red-500 rounded-xl hover:bg-red-100 transition-colors"
                        >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                        </button>
                      </div>
                    </div>
                  );
                })}
                <button 
                  type="button" 
                  onClick={() => setFormData(p => ({ ...p, medications: [...(p.medications || []), { name: '', dosage: '' }] }))} 
                  className="w-full py-5 bg-indigo-50 text-indigo-600 font-black rounded-3xl hover:bg-indigo-100 transition-all text-sm border-2 border-dashed border-indigo-200"
                >
                  + 添加联合治疗药物
                </button>
             </div>
          </div>
        </section>

        {/* 随访建议 */}
        <section className="bg-white/50 p-8 rounded-[2.5rem] border border-white shadow-sm">
           <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
             <svg className="w-6 h-6 text-orange-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             儿科随访管理
           </h3>
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                 {FOLLOW_UP_ITEMS.map(item => (
                   <div key={item} onClick={() => toggleItem(item)} className={`p-4 rounded-2xl border-2 transition-all cursor-pointer flex items-center justify-center text-center text-[10px] font-black leading-tight uppercase tracking-widest ${formData.followUpConfig?.items.includes(item) ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-black/5 text-gray-400 hover:border-indigo-200'}`}>
                     {item}
                   </div>
                 ))}
              </div>
              <div className="space-y-8">
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">随访间隔 (月)</label>
                       <input type="number" name="followUpConfig.intervalMonths" value={formData.followUpConfig?.intervalMonths} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-bold" />
