                <textarea name="clinicalSummary.eeg" value={formData.clinicalSummary?.eeg} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px]" placeholder="描述脑电特征..." />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">头颅 MRI/影像</label>
                <textarea name="clinicalSummary.mri" value={formData.clinicalSummary?.mri} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px]" placeholder="描述影像学表现..." />
