import React, { useState, useMemo } from 'react';
import { Patient, Gender } from '../types';

interface PatientListProps {
  patients: Patient[];
  onSelect: (patient: Patient) => void;
  onDelete: (id: string) => void;
  onDeleteMultiple: (ids: string[]) => void;
}

const PatientList: React.FC<PatientListProps> = ({ patients, onSelect, onDelete, onDeleteMultiple }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [showInsights, setShowInsights] = useState(false);

  // 1. 增强的过滤逻辑：支持药物、病情、基本信息的多维度模糊匹配
  const filteredPatients = useMemo(() => {
    return patients.filter(p => {
      const searchLower = searchTerm.toLowerCase();
      const matchesSearch = 
        p.name.toLowerCase().includes(searchLower) || 
        p.idCard.includes(searchTerm) ||
        p.phone.includes(searchTerm) ||
        p.diagnosis.toLowerCase().includes(searchLower) ||
        (p.clinicalSummary?.syndrome || '').toLowerCase().includes(searchLower) ||
        p.medications.some(m => m.name.toLowerCase().includes(searchLower));

      const patientDate = new Date(p.createdAt).toISOString().split('T')[0];
      const matchesStart = !startDate || patientDate >= startDate;
      const matchesEnd = !endDate || patientDate <= endDate;

      return matchesSearch && matchesStart && matchesEnd;
    });
  }, [patients, searchTerm, startDate, endDate]);

  // 2. 针对儿科优化的统计逻辑
  const stats = useMemo(() => {
    const total = filteredPatients.length;
    if (total === 0) return null;

    const genderCount = { male: 0, female: 0 };
    const ageGroups = {
      infant: 0,    // 婴儿期 (0-1岁)
      toddler: 0,   // 幼儿期 (1-3岁)
      preschool: 0, // 学龄前期 (3-6岁)
      school: 0,    // 学龄期 (6-12岁)
      adolescent: 0 // 青春期 (12-18岁+)
    };
    const medUsage: Record<string, number> = {};
    const diagnosisUsage: Record<string, number> = {};

    filteredPatients.forEach(p => {
      if (p.gender === Gender.MALE) genderCount.male++;
      else genderCount.female++;

      if (p.age <= 1) ageGroups.infant++;
      else if (p.age <= 3) ageGroups.toddler++;
      else if (p.age <= 6) ageGroups.preschool++;
      else if (p.age <= 12) ageGroups.school++;
      else ageGroups.adolescent++;

      p.medications.forEach(m => {
        const name = m.name.split(' ')[0].trim();
        if (name) medUsage[name] = (medUsage[name] || 0) + 1;
      });

      const diag = p.diagnosis.trim();
      if (diag) diagnosisUsage[diag] = (diagnosisUsage[diag] || 0) + 1;
    });

    const topMeds = Object.entries(medUsage).sort((a, b) => b[1] - a[1]).slice(0, 5);
    const topDiags = Object.entries(diagnosisUsage).sort((a, b) => b[1] - a[1]).slice(0, 5);

    return { total, genderCount, ageGroups, topMeds, topDiags };
  }, [filteredPatients]);

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSelectedIds(e.target.checked ? filteredPatients.map(p => p.id) : []);
  };

  const handleSelectOne = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return;
    onDeleteMultiple(selectedIds);
    setSelectedIds([]);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-24">
      {/* 高级筛选面板 */}
      <div className="glass rounded-[2.5rem] p-8 shadow-xl space-y-6 border-white/40">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 bg-indigo-500 rounded-[1.25rem] flex items-center justify-center text-white shadow-lg shadow-indigo-200">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
            </div>
            <div>
              <h2 className="text-2xl font-black text-gray-900">儿科随访智能查询</h2>
              <p className="text-indigo-500 text-[10px] font-black uppercase tracking-[0.2em] mt-0.5">Pediatric Epilepsy Database</p>
            </div>
          </div>

          <div className="flex items-center bg-gray-100/80 p-1.5 rounded-2xl border border-gray-200/50">
             <button 
               onClick={() => setShowInsights(false)}
               className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${!showInsights ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
               档案列表
             </button>
             <button 
               onClick={() => setShowInsights(true)}
               className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${showInsights ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
             >
               分布视图
             </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-4">
          <div className="relative group lg:col-span-6">
            <input 
              type="text" 
              placeholder="搜索：患儿姓名、药物名称、诊断症状..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-4 bg-white/60 border-2 border-transparent rounded-2xl focus:border-indigo-500/20 focus:bg-white outline-none transition-all font-bold text-gray-700 shadow-inner"
            />
            <svg className="w-5 h-5 text-gray-400 absolute left-4 top-[1.15rem] group-focus-within:text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
          </div>

          <div className="lg:col-span-4 flex gap-2">
             <div className="flex-1 relative">
                <span className="absolute left-4 top-1 text-[8px] font-black text-indigo-400 uppercase">From</span>
                <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full pl-4 pr-2 pt-5 pb-2 bg-white/60 border-0 rounded-2xl outline-none font-bold text-xs" />
             </div>
             <div className="flex-1 relative">
                <span className="absolute left-4 top-1 text-[8px] font-black text-indigo-400 uppercase">To</span>
                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full pl-4 pr-2 pt-5 pb-2 bg-white/60 border-0 rounded-2xl outline-none font-bold text-xs" />
             </div>
          </div>

          <button onClick={() => {setSearchTerm(''); setStartDate(''); setEndDate('');}} className="lg:col-span-2 py-4 bg-white border border-gray-200 text-gray-500 rounded-2xl font-bold text-xs hover:bg-gray-50 transition active:scale-95">
            重置筛选
          </button>
        </div>
      </div>

      {showInsights && stats ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in">
          {/* 可视化组件逻辑保持不变，确保 stats 包含所需数据 */}
          <div className="glass rounded-[2.5rem] p-8 flex flex-col items-center justify-center space-y-6 border-white/40 shadow-xl">
            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">患儿性别分布</h3>
            <div className="relative w-44 h-44">
               <svg className="w-full h-full transform -rotate-90">
                 <circle cx="88" cy="88" r="74" fill="transparent" stroke="#f472b6" strokeWidth="18" />
                 <circle cx="88" cy="88" r="74" fill="transparent" stroke="#6366f1" strokeWidth="18" 
                    strokeDasharray={465}
                    strokeDashoffset={465 * (1 - stats.genderCount.male / stats.total)}
                    className="transition-all duration-1000 ease-out"
                 />
               </svg>
               <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-4xl font-black text-gray-900">{Math.round((stats.genderCount.male / stats.total) * 100)}%</span>
               </div>
            </div>
            <div className="flex gap-10 w-full pt-2">
               <div className="flex-1 text-center">
                  <div className="text-indigo-600 font-black text-2xl">{stats.genderCount.male}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase">男</div>
               </div>
               <div className="flex-1 text-center">
                  <div className="text-pink-500 font-black text-2xl">{stats.genderCount.female}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase">女</div>
               </div>
            </div>
          </div>

          <div className="glass rounded-[2.5rem] p-8 space-y-6 border-white/40 shadow-xl">
            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">儿科年龄阶段分布</h3>
            <div className="space-y-4">
              {[
                { label: '婴儿 (0-1岁)', count: stats.ageGroups.infant, color: 'bg-rose-400' },
                { label: '幼儿 (1-3岁)', count: stats.ageGroups.toddler, color: 'bg-orange-400' },
                { label: '学龄前 (3-6岁)', count: stats.ageGroups.preschool, color: 'bg-amber-400' },
                { label: '学龄 (6-12岁)', count: stats.ageGroups.school, color: 'bg-emerald-400' },
                { label: '青春 (12-18岁+)', count: stats.ageGroups.adolescent, color: 'bg-indigo-400' },
              ].map((item, i) => (
                <div key={i} className="space-y-1.5">
                   <div className="flex justify-between text-[10px] font-black uppercase">
                      <span className="text-gray-500">{item.label}</span>
                      <span className="text-gray-900">{item.count} 人</span>
                   </div>
                   <div className="w-full h-2.5 bg-gray-100 rounded-full overflow-hidden">
                      <div className={`h-full ${item.color} transition-all duration-1000 ease-out`} style={{ width: `${(item.count / stats.total) * 100}%` }}></div>
                   </div>
                </div>
              ))}
            </div>
          </div>

          <div className="glass rounded-[2.5rem] p-8 space-y-6 border-white/40 shadow-xl">
            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">用药热度 (Top 5)</h3>
            <div className="space-y-5">
               {stats.topMeds.map(([name, count], i) => (
                 <div key={i} className="flex items-center gap-4">
                    <div className="w-8 h-8 rounded-xl bg-indigo-50 flex items-center justify-center text-xs font-black text-indigo-500">{i+1}</div>
                    <div className="flex-1 space-y-1">
                       <div className="flex justify-between items-center">
                          <span className="text-sm font-bold text-gray-800">{name}</span>
                          <span className="text-indigo-600 text-xs font-black">{count} 例</span>
                       </div>
                    </div>
                 </div>
               ))}
            </div>
          </div>
        </div>
      ) : (
        /* 数据表格视图 */
        <div className="glass rounded-[2.5rem] overflow-hidden shadow-2xl border-white/40">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white/30 border-b border-white/20">
                  <th className="px-6 py-6 w-12 text-center">
                    <input type="checkbox" onChange={handleSelectAll} checked={selectedIds.length === filteredPatients.length && filteredPatients.length > 0} className="w-5 h-5 rounded-md border-gray-300 text-indigo-600" />
                  </th>
                  <th className="px-4 py-6 text-[10px] font-black text-gray-400 uppercase tracking-widest">患儿信息</th>
                  <th className="px-4 py-6 text-[10px] font-black text-gray-400 uppercase tracking-widest">临床状况</th>
                  <th className="px-4 py-6 text-[10px] font-black text-gray-400 uppercase tracking-widest">治疗方案</th>
                  <th className="px-4 py-6 text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">操作</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/20">
                {filteredPatients.map((p) => {
                  const isSelected = selectedIds.includes(p.id);
                  return (
                    <tr key={p.id} className={`transition-all duration-300 ${isSelected ? 'bg-indigo-500/10' : 'hover:bg-white/40'}`}>
                      <td className="px-6 py-6 text-center">
                        <input type="checkbox" checked={isSelected} onChange={() => handleSelectOne(p.id)} className="w-5 h-5 rounded-md border-gray-300 text-indigo-600 cursor-pointer" />
                      </td>
                      <td className="px-4 py-6" onClick={() => onSelect(p)}>
                        <div className="flex items-center gap-4 cursor-pointer">
                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-white font-black shadow-lg ${p.gender === Gender.MALE ? 'bg-blue-400' : 'bg-pink-400'}`}>
                            {p.name[0]}
                          </div>
                          <div>
                            <div className="font-black text-gray-900 text-lg leading-tight">{p.name}</div>
                            <div className="text-[10px] font-black text-gray-400 mt-1 uppercase">{p.gender} · {p.age} 岁</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-6">
                        <div className="flex flex-col gap-1.5">
                          <span className="inline-block px-3 py-1 bg-white/80 text-gray-800 text-xs font-black rounded-lg border border-gray-200 max-w-fit">{p.diagnosis}</span>
                          {p.clinicalSummary?.syndrome && (
                            <span className="inline-block px-3 py-1 bg-indigo-50 text-indigo-700 text-[9px] font-black rounded-lg border border-indigo-100 max-w-fit">{p.clinicalSummary.syndrome}</span>
                          )}
                        </div>
                      </td>
                      <td className="px-4 py-6">
                        <div className="flex flex-wrap gap-1.5 max-w-[280px]">
                          {p.medications.map((m, i) => (
                            <div key={i} className="flex flex-col px-2.5 py-1.5 bg-white border border-gray-100 rounded-xl shadow-sm">
                              <span className="text-[10px] font-black text-indigo-600 leading-none">{m.name.split(' ')[0]}</span>
                              <span className="text-[8px] font-bold text-gray-400 mt-1">{m.usage} · {m.amount}</span>
                            </div>
                          ))}
                        </div>
                      </td>
                      <td className="px-4 py-6">
                        <div className="flex items-center justify-center gap-2">
                           <button onClick={() => onDelete(p.id)} className="p-3 bg-red-50 text-red-400 hover:bg-red-500 hover:text-white rounded-xl transition-all">
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                           </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {selectedIds.length > 0 && (
        <div className="fixed bottom-10 left-1/2 transform -translate-x-1/2 glass px-10 py-6 rounded-[2rem] flex items-center gap-12 shadow-2xl animate-fade-in z-50">
           <span className="text-sm font-black text-gray-900">已选中 {selectedIds.length} 名患儿</span>
           <div className="flex gap-4">
              <button onClick={handleBatchDelete} className="px-8 py-3 bg-red-500 text-white text-xs font-black rounded-2xl shadow-lg hover:bg-red-600 transition">批量移除</button>
              <button onClick={() => setSelectedIds([])} className="px-8 py-3 bg-gray-200 text-gray-700 text-xs font-black rounded-2xl hover:bg-gray-300 transition">取消</button>
           </div>
        </div>
      )}
    </div>
  );
};

export default PatientList;

import React, { useState, useEffect } from 'react';
import Dashboard from './components/Dashboard';
import PatientForm from './components/PatientForm';
import PatientList from './components/PatientList';
import { storage } from './services/storage';
import { Patient } from './types';

enum View {
  DASHBOARD = 'DASHBOARD',
  LIST = 'LIST',
  FORM = 'FORM'
}

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.DASHBOARD);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [editingPatient, setEditingPatient] = useState<Patient | undefined>(undefined);

  useEffect(() => {
    setPatients(storage.getPatients());
  }, []);

  const handleSavePatient = (patient: Patient) => {
    if (editingPatient) {
      storage.updatePatient(patient);
    } else {
      storage.addPatient(patient);
    }
    setPatients(storage.getPatients());
    setActiveView(View.DASHBOARD);
    setEditingPatient(undefined);
  };

  const handleDeletePatient = (id: string) => {
    if (window.confirm('确认删除该病人记录？此操作无法撤销。')) {
      storage.deletePatient(id);
      setPatients(storage.getPatients());
    }
  };

  const handleDeleteMultiplePatients = (ids: string[]) => {
    if (window.confirm(`确定要永久删除选中的 ${ids.length} 名患者记录吗？`)) {
      const allPatients = storage.getPatients();
      const filtered = allPatients.filter(p => !ids.includes(p.id));
      storage.savePatients(filtered);
      setPatients(filtered);
    }
  };

  const handleEditPatient = (patient: Patient) => {
    setEditingPatient(patient);
    setActiveView(View.FORM);
  };

  return (
    <div className="min-h-screen flex flex-col pb-20 md:pb-0">
      <header className="sticky top-0 z-50 glass border-b-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center gap-3">
              <div className="w-12 h-12 bg-gradient-to-br from-violet-400 to-violet-600 rounded-2xl flex items-center justify-center text-white font-black italic shadow-lg">
                LZ
              </div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight hidden sm:block">LZRYEK 癫痫随访</h1>
            </div>

            <nav className="flex space-x-1.5 bg-black/5 p-1.5 rounded-2xl">
              {[
                { id: View.DASHBOARD, label: '概览', icon: 'M4 6h16M4 12h16M4 18h16' },
                { id: View.LIST, label: '查询', icon: 'M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z' },
                { id: View.FORM, label: '录入', icon: 'M12 4v16m8-8H4' },
              ].map(item => (
                <button
                  key={item.id}
                  onClick={() => {
                    setActiveView(item.id);
                    if (item.id !== View.FORM) setEditingPatient(undefined);
                  }}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 ${
                    activeView === item.id 
                    ? 'bg-white shadow-sm text-violet-600' 
                    : 'text-gray-500 hover:text-gray-900'
                  }`}
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path>
                  </svg>
                  <span className="hidden md:inline">{item.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        {activeView === View.DASHBOARD && (
          <Dashboard 
            patients={patients} 
            onSelectPatient={handleEditPatient} 
            onAddClick={() => setActiveView(View.FORM)}
          />
        )}

        {activeView === View.LIST && (
          <PatientList 
            patients={patients} 
            onSelect={handleEditPatient} 
            onDelete={handleDeletePatient}
            onDeleteMultiple={handleDeleteMultiplePatients}
          />
        )}

        {activeView === View.FORM && (
          <PatientForm 
            initialData={editingPatient}
            onSubmit={handleSavePatient}
            onCancel={() => {
              setActiveView(View.DASHBOARD);
              setEditingPatient(undefined);
            }}
          />
        )}
      </main>

      <footer className="mt-auto py-8 text-center text-gray-600 text-xs px-4">
        <p className="opacity-75">© 2024 LZRYEK Epilepsy Management. <i>By Jefflong</i></p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { Patient, FollowUpReminder } from '../types';

interface DashboardProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddClick: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ patients, onSelectPatient, onAddClick }) => {
  const getReminders = (): FollowUpReminder[] => {
    const today = new Date();
    return patients
      .map(p => {
        const nextDate = new Date(p.followUpConfig.nextFollowUpDate);
        const diffTime = nextDate.getTime() - today.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        return {
          patientId: p.id,
          patientName: p.name,
          daysRemaining: diffDays,
          isOverdue: diffDays < 0,
          dueDate: p.followUpConfig.nextFollowUpDate
        };
      })
      .filter(r => r.daysRemaining <= 14) 
      .sort((a, b) => a.daysRemaining - b.daysRemaining);
  };

  const reminders = getReminders();

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fade-in">
      <div className="lg:col-span-2 space-y-8">
        <div className="glass rounded-[2rem] p-8 overflow-hidden">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h2 className="text-2xl font-bold text-gray-900 tracking-tight">随访任务清单</h2>
              <p className="text-gray-500 text-sm mt-1">未来 14 天内需要处理的随访</p>
            </div>
            <span className="bg-white/50 backdrop-blur-sm text-gray-700 text-xs font-bold px-4 py-1.5 rounded-full border border-white/50">{reminders.length} 个任务</span>
          </div>

          {reminders.length > 0 ? (
            <div className="space-y-4">
              {reminders.map((reminder) => (
                <div 
                  key={reminder.patientId}
                  onClick={() => {
                    const patient = patients.find(p => p.id === reminder.patientId);
                    if (patient) onSelectPatient(patient);
                  }}
                  className={`flex items-center justify-between p-5 rounded-2xl transition-all active:scale-[0.98] cursor-pointer group glass-dark border-0 hover:bg-white/60`}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold shadow-sm ${reminder.isOverdue ? 'bg-fuchsia-500 text-white' : 'bg-sky-400 text-white'}`}>
                      {reminder.patientName[0]}
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-900 text-lg">{reminder.patientName}</h4>
                      <p className="text-xs text-gray-500 font-medium">随访日期: {reminder.dueDate}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    {reminder.isOverdue ? (
                      <span className="text-fuchsia-600 font-bold bg-fuchsia-100 px-3 py-1 rounded-full text-xs">
                        已逾期 {Math.abs(reminder.daysRemaining)} 天
                      </span>
                    ) : (
                      <span className="text-sky-700 font-bold bg-sky-100 px-3 py-1 rounded-full text-xs">
                        {reminder.daysRemaining === 0 ? '就在今天' : `${reminder.daysRemaining} 天后`}
                      </span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-16 glass-dark rounded-3xl border-0 border-dashed border-white/40">
              <div className="w-16 h-16 bg-white/50 rounded-full flex items-center justify-center mx-auto mb-4">
                 <svg className="w-8 h-8 text-sky-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7"></path></svg>
              </div>
              <p className="text-gray-600 font-semibold text-lg">暂无待办</p>
              <p className="text-gray-400 text-sm">随访计划已全部跟进</p>
            </div>
          )}
        </div>
      </div>

      <div className="space-y-8">
