import React, { useState, useMemo } from 'react';
import { Patient, Gender } from '../types';

interface PatientListProps {
  patients: Patient[];
  onSelect: (patient: Patient) => void;
  onDelete: (id: string) => void;
  onDeleteMultiple: (ids: string[]) => void;
}

const PatientList: React.FC<PatientListProps> = ({ patients, onSelect, onDelete, onDeleteMultiple }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [showInsights, setShowInsights] = useState(false);

  // 1. 增强的过滤逻辑：支持药物、病情、基本信息的多维度模糊匹配
  const filteredPatients = useMemo(() => {
    return patients.filter(p => {
      const searchLower = searchTerm.toLowerCase();
      const matchesSearch = 
        p.name.toLowerCase().includes(searchLower) || 
        p.idCard.includes(searchTerm) ||
        p.phone.includes(searchTerm) ||
        p.diagnosis.toLowerCase().includes(searchLower) ||
        (p.clinicalSummary?.syndrome || '').toLowerCase().includes(searchLower) ||
        p.medications.some(m => m.name.toLowerCase().includes(searchLower));

      const patientDate = new Date(p.createdAt).toISOString().split('T')[0];
      const matchesStart = !startDate || patientDate >= startDate;
      const matchesEnd = !endDate || patientDate <= endDate;

      return matchesSearch && matchesStart && matchesEnd;
    });
  }, [patients, searchTerm, startDate, endDate]);

  // 2. 针对儿科优化的统计逻辑
  const stats = useMemo(() => {
    const total = filteredPatients.length;
    if (total === 0) return null;

    const genderCount = { male: 0, female: 0 };
    const ageGroups = {
      infant: 0,    // 婴儿期 (0-1岁)
      toddler: 0,   // 幼儿期 (1-3岁)
      preschool: 0, // 学龄前期 (3-6岁)
      school: 0,    // 学龄期 (6-12岁)
      adolescent: 0 // 青春期 (12-18岁+)
    };
    const medUsage: Record<string, number> = {};
    const diagnosisUsage: Record<string, number> = {};

    filteredPatients.forEach(p => {
      if (p.gender === Gender.MALE) genderCount.male++;
      else genderCount.female++;

      if (p.age <= 1) ageGroups.infant++;
      else if (p.age <= 3) ageGroups.toddler++;
      else if (p.age <= 6) ageGroups.preschool++;
      else if (p.age <= 12) ageGroups.school++;
      else ageGroups.adolescent++;

      p.medications.forEach(m => {
        const name = m.name.split(' ')[0].trim();
        if (name) medUsage[name] = (medUsage[name] || 0) + 1;
      });

      const diag = p.diagnosis.trim();
      if (diag) diagnosisUsage[diag] = (diagnosisUsage[diag] || 0) + 1;
    });

    const topMeds = Object.entries(medUsage).sort((a, b) => b[1] - a[1]).slice(0, 5);
    const topDiags = Object.entries(diagnosisUsage).sort((a, b) => b[1] - a[1]).slice(0, 5);

    return { total, genderCount, ageGroups, topMeds, topDiags };
  }, [filteredPatients]);

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSelectedIds(e.target.checked ? filteredPatients.map(p => p.id) : []);
  };

  const handleSelectOne = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return;
    onDeleteMultiple(selectedIds);
    setSelectedIds([]);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-24">
      {/* 高级筛选面板 */}
