import React, { useState } from 'react';
import { Patient, AssessmentRecord } from '../types';
import { storage } from '../services/storage';

interface AssessmentToolProps {
  patients: Patient[];
  onSaved: () => void;
}

const AssessmentTool: React.FC<AssessmentToolProps> = ({ patients, onSaved }) => {
  const [selectedPatientId, setSelectedPatientId] = useState<string>('');
  const [scores, setScores] = useState({
    emotional: 5,
    social: 5,
    seizure: 5,
    sideEffect: 5,
    overall: 5
  });
  const [notes, setNotes] = useState('');

  const handleSliderChange = (key: keyof typeof scores, val: string) => {
    setScores(prev => ({ ...prev, [key]: parseInt(val) }));
  };

  const calculateTotal = () => {
    const sum = scores.emotional + scores.social + scores.seizure + (10 - scores.sideEffect) + scores.overall;
    return (sum / 50) * 100;
  };

  const handleSave = () => {
    if (!selectedPatientId) return alert('请先选择病人');
    const patient = patients.find(p => p.id === selectedPatientId);
    if (!patient) return;

    const newRecord: AssessmentRecord = {
      id: crypto.randomUUID(),
      date: new Date().toISOString().split('T')[0],
      scores: { ...scores },
      totalScore: Math.round(calculateTotal()),
      notes
    };

    const updatedPatient = {
      ...patient,
      assessmentHistory: [...(patient.assessmentHistory || []), newRecord]
    };

    storage.updatePatient(updatedPatient);
    onSaved();
  };

  const getAdvice = (score: number) => {
    if (score >= 80) return { text: '生活质量优良', color: 'text-violet-600', bg: 'bg-violet-50' };
    if (score >= 60) return { text: '生活质量一般', color: 'text-sky-600', bg: 'bg-sky-50' };
    return { text: '生活质量较差，需重点关注', color: 'text-fuchsia-600', bg: 'bg-fuchsia-50' };
  };

  const currentScore = calculateTotal();
  const advice = getAdvice(currentScore);

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      <div className="glass rounded-[2.5rem] p-8 shadow-2xl border-white/40">
        <h2 className="text-3xl font-black text-gray-900 mb-8 flex items-center gap-3">
           <div className="w-12 h-12 bg-violet-500 rounded-2xl flex items-center justify-center text-white shadow-lg">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"></path></svg>
           </div>
           QOLIE 生活质量评估
        </h2>

        <div className="space-y-10">
          {/* 病人选择 */}
          <div className="space-y-3">
             <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">受试患儿</label>
             <select 
               value={selectedPatientId}
               onChange={(e) => setSelectedPatientId(e.target.value)}
               className="w-full px-6 py-4 bg-white/60 border-0 rounded-2xl focus:ring-4 focus:ring-violet-500/20 outline-none font-bold text-gray-800 appearance-none shadow-sm"
             >
               <option value="">点击选择待评估患儿...</option>
               {patients.map(p => (
                 <option key={p.id} value={p.id}>{p.name} ({p.gender} | {p.age}岁)</option>
               ))}
             </select>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
            {/* 评分项 */}
            <div className="space-y-8">
               {[
                 { key: 'emotional', label: '情绪状态', desc: '焦虑、沮丧或易怒程度', color: 'accent-violet-500' },
                 { key: 'social', label: '社会功能', desc: '学习、社交及家庭生活影响', color: 'accent-sky-400' },
                 { key: 'seizure', label: '发作担忧', desc: '对下次发作的恐惧程度', color: 'accent-fuchsia-400' },
                 { key: 'sideEffect', label: '药物副作用', desc: '乏力、头晕或认知干扰', color: 'accent-violet-400' },
                 { key: 'overall', label: '整体满意度', desc: '您对目前生活水平的评价', color: 'accent-sky-500' },
               ].map((item) => (
                 <div key={item.key} className="space-y-3">
                   <div className="flex justify-between items-end">
                      <div>
                        <h4 className="font-bold text-gray-800">{item.label}</h4>
                        <p className="text-[10px] text-gray-400 font-medium">{item.desc}</p>
                      </div>
                      <span className="text-xl font-black text-violet-600">{scores[item.key as keyof typeof scores]}</span>
                   </div>
                   <input 
                     type="range" 
                     min="0" max="10" 
                     value={scores[item.key as keyof typeof scores]}
                     onChange={(e) => handleSliderChange(item.key as keyof typeof scores, e.target.value)}
                     className={`w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer ${item.color}`}
                   />
                 </div>
               ))}
            </div>

            {/* 结果展示 */}
            <div className="flex flex-col items-center justify-center space-y-8 bg-white/40 rounded-[2rem] p-8 border border-white/50 shadow-inner">
               <div className="relative flex items-center justify-center">
                  <svg className="w-48 h-48 transform -rotate-90">
                    <circle cx="96" cy="96" r="80" stroke="currentColor" strokeWidth="16" fill="transparent" className="text-gray-100/50" />
                    <circle cx="96" cy="96" r="80" stroke="currentColor" strokeWidth="16" fill="transparent" 
                      strokeDasharray={2 * Math.PI * 80}
                      strokeDashoffset={2 * Math.PI * 80 * (1 - currentScore / 100)}
                      className="text-violet-500 transition-all duration-1000 ease-out"
                    />
                  </svg>
                  <div className="absolute flex flex-col items-center">
                     <span className="text-5xl font-black tracking-tighter text-gray-900">{Math.round(currentScore)}</span>
                     <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">综合指数</span>
                  </div>
               </div>

               <div className={`w-full p-6 rounded-2xl text-center transition-colors ${advice.bg} shadow-sm border border-white/40`}>
                  <h5 className={`font-black text-lg ${advice.color}`}>{advice.text}</h5>
                  <p className="text-xs text-gray-500 mt-1 font-medium italic">基于儿科 QOLIE 简化评分</p>
               </div>

               <div className="w-full space-y-1.5">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">评估备注 (可选)</label>
                  <textarea 
                    value={notes}
                    onChange={(e) => setNotes(e.target.value)}
                    placeholder="记录此次评估的关键观察点..."
                    className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[100px] focus:ring-4 focus:ring-violet-500/10"
                  />
               </div>
            </div>
          </div>

          <div className="flex gap-4 pt-4">
             <button 
               onClick={handleSave}
               className="flex-1 bg-violet-600 text-white font-black py-5 rounded-[1.5rem] shadow-xl hover:bg-violet-700 transition-all active:scale-95 text-lg"
             >
               保存评估记录
             </button>
             <button 
               onClick={() => window.history.back()}
               className="px-8 py-5 bg-white/80 text-gray-600 font-bold rounded-[1.5rem] transition-all hover:bg-white"
             >
               取消
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AssessmentTool;

export enum Gender {
  MALE = '男',
  FEMALE = '女'
}

/**
 * AssessmentRecord represents a single Quality of Life (QOLIE-31) assessment result
 * for a patient, tracking various dimensions of their well-being.
 */
export interface AssessmentRecord {
  id: string;
  date: string;
  scores: {
    emotional: number;
    social: number;
    seizure: number;
    sideEffect: number;
    overall: number;
  };
  totalScore: number;
  notes: string;
}

export interface Patient {
  id: string;
  name: string;
  gender: Gender;
  age: number;
  allergies: string; // 过敏史
  idCard: string;
  phone: string;
  clinicalSummary: {
    syndrome: string; // 癫痫综合征
    seizureType: string;
    eeg: string;
    mri: string;
    genetic: string;
    other: string;
  };
  diagnosis: string;
  diagnosisDate: string;
  medications: Medication[];
  followUpConfig: {
    items: string[];
    intervalMonths: number;
    lastFollowUpDate: string;
    nextFollowUpDate: string;
  };
  /**
   * assessmentHistory stores a collection of quality of life assessments
   * over time for clinical evaluation.
   */
  assessmentHistory?: AssessmentRecord[];
  createdAt: number;
}

export interface Medication {
  name: string;
  usage: string;  // 用法，如: 口服 bid
  amount: string; // 用量，如: 0.25g
}

export interface FollowUpReminder {
  patientId: string;
  patientName: string;
  daysRemaining: number;
  isOverdue: boolean;
  dueDate: string;
}

import React, { useState, useEffect } from 'react';
import { Patient, Gender, Medication } from '../types';
import { COMMON_MEDICATIONS, FOLLOW_UP_ITEMS } from '../constants';

interface PatientFormProps {
  initialData?: Patient;
  onSubmit: (data: Patient) => void;
  onCancel: () => void;
}

const PatientForm: React.FC<PatientFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '',
    gender: Gender.MALE,
    age: 0,
    allergies: '',
    idCard: '',
    phone: '',
    clinicalSummary: { 
      syndrome: '', 
      seizureType: '', 
      eeg: '', 
      mri: '', 
      genetic: '', 
      other: '' 
    },
    diagnosis: '',
    diagnosisDate: new Date().toISOString().split('T')[0],
    medications: [{ name: '', usage: '', amount: '' }],
    followUpConfig: { 
      items: [], 
      intervalMonths: 3, 
      lastFollowUpDate: new Date().toISOString().split('T')[0], 
      nextFollowUpDate: '' 
    }
  });

  const [otherFollowUpText, setOtherFollowUpText] = useState('');

  useEffect(() => { 
    if (initialData) {
      setFormData(initialData);
      // 检查是否有不在预设列表中的随访项目（即“其他”的内容）
      const customItem = initialData.followUpConfig.items.find(item => !FOLLOW_UP_ITEMS.includes(item));
      if (customItem) setOtherFollowUpText(customItem);
    } 
  }, [initialData]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({ 
        ...prev, 
        [parent]: { ...(prev[parent as keyof Patient] as any), [child]: value } 
      }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleMedicationChange = (index: number, field: keyof Medication, value: string) => {
    const newMeds = [...(formData.medications || [])];
    newMeds[index] = { ...newMeds[index], [field]: value };
    setFormData(prev => ({ ...prev, medications: newMeds }));
  };

  const calculateNextDate = () => {
    if (!formData.followUpConfig?.lastFollowUpDate || !formData.followUpConfig?.intervalMonths) return;
    const lastDate = new Date(formData.followUpConfig.lastFollowUpDate);
    lastDate.setMonth(lastDate.getMonth() + Number(formData.followUpConfig.intervalMonths));
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { ...prev.followUpConfig!, nextFollowUpDate: lastDate.toISOString().split('T')[0] } 
    }));
  };

  useEffect(() => { calculateNextDate(); }, [formData.followUpConfig?.lastFollowUpDate, formData.followUpConfig?.intervalMonths]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // 处理随访项目中的“其他”
    let finalItems = [...(formData.followUpConfig?.items || [])].filter(i => i !== '其他');
    const predefinedExceptOther = FOLLOW_UP_ITEMS.filter(i => i !== '其他');
    // 移除所有非预设的项目，然后如果 otherFollowUpText 有值，加入它
    finalItems = finalItems.filter(i => predefinedExceptOther.includes(i));
    if (formData.followUpConfig?.items.includes('其他') && otherFollowUpText.trim()) {
      finalItems.push(otherFollowUpText.trim());
    } else if (formData.followUpConfig?.items.includes('其他')) {
      finalItems.push('其他');
    }

    const finalMeds = (formData.medications || []).map(m => ({
      ...m,
      name: m.name === ' ' ? '' : m.name
    }));

    onSubmit({ 
      ...(formData as Patient), 
      medications: finalMeds, 
      followUpConfig: {
        ...formData.followUpConfig!,
        items: finalItems
      },
      id: initialData?.id || crypto.randomUUID(), 
      createdAt: initialData?.createdAt || Date.now() 
    });
  };

  const toggleItem = (item: string) => {
    const items = formData.followUpConfig?.items || [];
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { 
        ...prev.followUpConfig!, 
        items: items.includes(item) ? items.filter(i => i !== item) : [...items, item] 
      } 
    }));
  };

  return (
    <form onSubmit={handleSubmit} className="glass rounded-[2.5rem] p-8 space-y-10 animate-fade-in overflow-y-auto max-h-[85vh] shadow-2xl text-gray-900 border-white/40">
      <div className="flex justify-between items-center pb-6 border-b border-white/30">
        <div>
           <h2 className="text-3xl font-black text-gray-900 tracking-tight">
             {initialData ? '更新患儿档案' : '儿科病例录入'}
           </h2>
           <p className="text-violet-500 text-xs font-black uppercase tracking-[0.2em] mt-1">
             Pediatric Clinical Records
           </p>
        </div>
        <button type="button" onClick={onCancel} className="p-3 bg-black/5 hover:bg-black/10 rounded-full transition-colors">
          <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
      </div>

      <div className="space-y-12">
        {/* 基本身份信息 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-violet-500 rounded-full"></div>
             <h3 className="text-lg font-bold">基本身份信息</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 bg-white/40 p-8 rounded-[2rem] border border-white/50 shadow-inner">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">患儿姓名</label>
              <input name="name" value={formData.name} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20 outline-none transition-all font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">性别</label>
              <select name="gender" value={formData.gender} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold">
                <option value={Gender.MALE}>男 (Boy)</option>
                <option value={Gender.FEMALE}>女 (Girl)</option>
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">当前年龄</label>
              <input type="number" name="age" value={formData.age} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-fuchsia-500 uppercase tracking-widest px-1">过敏史</label>
              <input name="allergies" value={formData.allergies} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-fuchsia-500/20 outline-none transition-all font-semibold" placeholder="药物/食物过敏情况" />
            </div>
          </div>
        </section>

        {/* 临床概况 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-sky-400 rounded-full"></div>
             <h3 className="text-lg font-bold">临床概况与医学检查</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">临床诊断</label>
                <input name="diagnosis" value={formData.diagnosis} onChange={handleInputChange} className="w-full px-6 py-5 bg-white/80 border-2 border-sky-400/30 rounded-2xl shadow-sm outline-none font-black text-lg text-sky-700" placeholder="如: 局灶性癫痫" required />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">癫痫综合征</label>
                <input name="clinicalSummary.syndrome" value={formData.clinicalSummary?.syndrome} onChange={handleInputChange} className="w-full px-6 py-5 bg-white/80 border-2 border-violet-500/30 rounded-2xl shadow-sm outline-none font-black text-lg text-violet-700" placeholder="如: West 综合征" />
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">发作形式特征</label>
              <textarea name="clinicalSummary.seizureType" value={formData.clinicalSummary?.seizureType} onChange={handleInputChange} className="w-full px-6 py-4 bg-white/60 rounded-2xl outline-none min-h-[80px] text-sm font-medium" placeholder="描述发作的具体动作、持续时间、伴随症状等..." />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-violet-400 uppercase tracking-widest">脑电图 (EEG)</label>
                <textarea name="clinicalSummary.eeg" value={formData.clinicalSummary?.eeg} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px] focus:ring-2 focus:ring-violet-300" placeholder="描述脑电特征..." />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-sky-400 uppercase tracking-widest">头颅 MRI/影像</label>
                <textarea name="clinicalSummary.mri" value={formData.clinicalSummary?.mri} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px] focus:ring-2 focus:ring-sky-300" placeholder="描述影像学表现..." />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">基因/代谢筛选</label>
                <textarea name="clinicalSummary.genetic" value={formData.clinicalSummary?.genetic} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px] focus:ring-2 focus:ring-fuchsia-300" placeholder="记录基因检测结果..." />
              </div>
            </div>
          </div>
        </section>

        {/* 治疗与药物方案 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-fuchsia-500 rounded-full"></div>
             <h3 className="text-lg font-bold">治疗与药物方案</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0">
             <div className="space-y-6">
                {(formData.medications || []).map((med, idx) => {
                  const isKnown = COMMON_MEDICATIONS.includes(med.name);
                  const showManualInput = !isKnown && med.name !== '';

                  return (
                    <div key={idx} className="bg-white/50 p-6 rounded-3xl border border-white/50 space-y-4 shadow-sm relative group">
                      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 items-end">
                        <div className="lg:col-span-5 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">药物名称 (ASM)</label>
                          <select 
                            value={isKnown ? med.name : (med.name === '' ? '' : 'OTHER')}
                            onChange={(e) => {
                              const val = e.target.value;
                              if (val === 'OTHER') handleMedicationChange(idx, 'name', ' '); 
                              else handleMedicationChange(idx, 'name', val);
                            }}
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-bold border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20"
                          >
                            <option value="">选择药物...</option>
                            {COMMON_MEDICATIONS.map(m => <option key={m} value={m}>{m}</option>)}
                            <option value="OTHER">其他 (手动输入)...</option>
                          </select>
                          {showManualInput && (
                            <input 
                              autoFocus
                              value={med.name === ' ' ? '' : med.name}
                              onChange={(e) => handleMedicationChange(idx, 'name', e.target.value)}
                              className="w-full px-4 py-4 mt-2 bg-violet-50/50 border-2 border-violet-200 rounded-xl outline-none text-sm font-black text-violet-700"
                              placeholder="手动输入药物名称"
                            />
                          )}
                        </div>

                        <div className="lg:col-span-3 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">用法</label>
                          <input 
                            value={med.usage} 
                            onChange={(e) => handleMedicationChange(idx, 'usage', e.target.value)} 
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20" 
                            placeholder="如: 口服 bid" 
                          />
                        </div>

                        <div className="lg:col-span-3 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">用量</label>
                          <input 
                            value={med.amount} 
                            onChange={(e) => handleMedicationChange(idx, 'amount', e.target.value)} 
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20" 
                            placeholder="如: 0.25g" 
                          />
                        </div>

                        <div className="lg:col-span-1 pb-1 flex justify-center">
                          <button 
                            type="button" 
                            onClick={() => setFormData(p => ({ ...p, medications: p.medications?.filter((_, i) => i !== idx) }))} 
                            className="p-3 bg-fuchsia-50 text-fuchsia-500 rounded-xl hover:bg-fuchsia-500 hover:text-white transition-all"
                          >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                          </button>
                        </div>
                      </div>
                    </div>
                  );
                })}
                <button 
                  type="button" 
                  onClick={() => setFormData(p => ({ ...p, medications: [...(p.medications || []), { name: '', usage: '', amount: '' }] }))} 
                  className="w-full py-5 bg-violet-50 text-violet-600 font-black rounded-3xl hover:bg-violet-100 transition-all text-sm border-2 border-dashed border-violet-200"
                >
                  + 添加治疗药物
                </button>
             </div>
          </div>
        </section>

        {/* 儿科随访管理 */}
        <section className="bg-white/50 p-8 rounded-[2.5rem] border border-white shadow-sm">
           <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
             <svg className="w-6 h-6 text-sky-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             儿科随访管理
           </h3>
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="space-y-4">
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                   {FOLLOW_UP_ITEMS.map(item => (
                     <div 
                      key={item} 
                      onClick={() => toggleItem(item)} 
                      className={`p-3 rounded-2xl border-2 transition-all cursor-pointer flex items-center justify-center text-center text-[10px] font-black leading-tight uppercase tracking-widest ${formData.followUpConfig?.items.includes(item) ? 'bg-violet-600 border-violet-600 text-white shadow-lg' : 'bg-white border-black/5 text-gray-400 hover:border-violet-200'}`}
                     >
                       {item}
                     </div>
                   ))}
                </div>
                {formData.followUpConfig?.items.includes('其他') && (
                  <div className="animate-fade-in space-y-1.5">
                    <label className="text-[10px] font-black text-violet-500 uppercase tracking-widest ml-1">自定义随访内容</label>
                    <input 
                      type="text"
                      value={otherFollowUpText}
                      onChange={(e) => setOtherFollowUpText(e.target.value)}
                      placeholder="请输入具体的随访内容..."
                      className="w-full px-5 py-4 bg-white border-2 border-violet-100 rounded-2xl outline-none font-bold text-sm shadow-sm"
                    />
                  </div>
                )}
              </div>

              <div className="space-y-8">
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">随访间隔 (月)</label>
                       <input type="number" name="followUpConfig.intervalMonths" value={formData.followUpConfig?.intervalMonths} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-bold focus:ring-2 focus:ring-violet-200" />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">本次就诊日期</label>
                       <input type="date" name="followUpConfig.lastFollowUpDate" value={formData.followUpConfig?.lastFollowUpDate} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-bold text-sm focus:ring-2 focus:ring-violet-200" />
                    </div>
                 </div>
                 <div className="p-8 bg-gradient-to-br from-violet-600 to-sky-600 rounded-[2rem] text-white shadow-xl">
                    <span className="text-xs font-black text-violet-100 uppercase tracking-[0.2em] block mb-2">Next Appointment</span>
                    <span className="text-3xl font-black">{formData.followUpConfig?.nextFollowUpDate || '系统自动生成...'}</span>
                 </div>
              </div>
           </div>
        </section>
      </div>

      <div className="flex gap-6 pt-10 sticky bottom-0 bg-white/30 backdrop-blur-md -mx-8 px-8 pb-4 z-20">
        <button type="submit" className="flex-1 bg-violet-600 text-white font-black py-5 rounded-3xl shadow-2xl hover:bg-violet-700 transition-all text-lg active:scale-95">
          确认存档
        </button>
        <button type="button" onClick={onCancel} className="px-12 py-5 bg-white/80 text-gray-700 font-bold rounded-3xl hover:bg-white transition-all text-lg shadow-sm">
          取消
        </button>
      </div>
    </form>
  );
};

export default PatientForm;

export enum Gender {
  MALE = '男',
  FEMALE = '女'
}

/**
 * AssessmentRecord represents a single Quality of Life (QOLIE-31) assessment result
 * for a patient, tracking various dimensions of their well-being.
 */
export interface AssessmentRecord {
  id: string;
  date: string;
  scores: {
    emotional: number;
    social: number;
    seizure: number;
    sideEffect: number;
    overall: number;
  };
  totalScore: number;
  notes: string;
}

export interface Patient {
  id: string;
  name: string;
  gender: Gender;
  age: number;
  allergies: string; // 过敏史
  familyHistory: string; // 家族史
  idCard: string;
  phone: string;
  clinicalSummary: {
    syndrome: string; // 癫痫综合征
    seizureType: string;
    eeg: string;
    mri: string;
    genetic: string;
    other: string;
  };
  diagnosis: string;
  diagnosisDate: string;
  medications: Medication[];
  followUpConfig: {
    items: string[];
    intervalMonths: number;
    lastFollowUpDate: string;
    nextFollowUpDate: string;
  };
  /**
   * assessmentHistory stores a collection of quality of life assessments
   * over time for clinical evaluation.
   */
  assessmentHistory?: AssessmentRecord[];
  createdAt: number;
}

export interface Medication {
  name: string;
  usage: string;  // 用法，如: 口服 bid
  amount: string; // 用量，如: 0.25g
}

export interface FollowUpReminder {
  patientId: string;
  patientName: string;
  daysRemaining: number;
  isOverdue: boolean;
  dueDate: string;
}

import React, { useState, useEffect } from 'react';
import { Patient, Gender, Medication } from '../types';
import { COMMON_MEDICATIONS, FOLLOW_UP_ITEMS } from '../constants';

interface PatientFormProps {
  initialData?: Patient;
  onSubmit: (data: Patient) => void;
  onCancel: () => void;
}

const PatientForm: React.FC<PatientFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '',
    gender: Gender.MALE,
    age: 0,
    allergies: '',
    familyHistory: '',
    idCard: '',
    phone: '',
    clinicalSummary: { 
      syndrome: '', 
      seizureType: '', 
      eeg: '', 
      mri: '', 
      genetic: '', 
      other: '' 
    },
    diagnosis: '',
    diagnosisDate: new Date().toISOString().split('T')[0],
    medications: [{ name: '', usage: '', amount: '' }],
    followUpConfig: { 
      items: [], 
      intervalMonths: 3, 
      lastFollowUpDate: new Date().toISOString().split('T')[0], 
      nextFollowUpDate: '' 
    }
  });

  const [otherFollowUpText, setOtherFollowUpText] = useState('');

  useEffect(() => { 
    if (initialData) {
      setFormData(initialData);
      // 检查是否有不在预设列表中的随访项目（即“其他”的内容）
      const customItem = initialData.followUpConfig.items.find(item => !FOLLOW_UP_ITEMS.includes(item));
      if (customItem) setOtherFollowUpText(customItem);
    } 
  }, [initialData]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({ 
        ...prev, 
        [parent]: { ...(prev[parent as keyof Patient] as any), [child]: value } 
      }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleMedicationChange = (index: number, field: keyof Medication, value: string) => {
    const newMeds = [...(formData.medications || [])];
    newMeds[index] = { ...newMeds[index], [field]: value };
    setFormData(prev => ({ ...prev, medications: newMeds }));
  };

  const calculateNextDate = () => {
    if (!formData.followUpConfig?.lastFollowUpDate || !formData.followUpConfig?.intervalMonths) return;
    const lastDate = new Date(formData.followUpConfig.lastFollowUpDate);
    lastDate.setMonth(lastDate.getMonth() + Number(formData.followUpConfig.intervalMonths));
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { ...prev.followUpConfig!, nextFollowUpDate: lastDate.toISOString().split('T')[0] } 
    }));
  };

  useEffect(() => { calculateNextDate(); }, [formData.followUpConfig?.lastFollowUpDate, formData.followUpConfig?.intervalMonths]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // 处理随访项目中的“其他”
    let finalItems = [...(formData.followUpConfig?.items || [])].filter(i => i !== '其他');
    const predefinedExceptOther = FOLLOW_UP_ITEMS.filter(i => i !== '其他');
    // 移除所有非预设的项目，然后如果 otherFollowUpText 有值，加入它
    finalItems = finalItems.filter(i => predefinedExceptOther.includes(i));
    if (formData.followUpConfig?.items.includes('其他') && otherFollowUpText.trim()) {
      finalItems.push(otherFollowUpText.trim());
    } else if (formData.followUpConfig?.items.includes('其他')) {
      finalItems.push('其他');
    }

    const finalMeds = (formData.medications || []).map(m => ({
      ...m,
      name: m.name === ' ' ? '' : m.name
    }));

    onSubmit({ 
      ...(formData as Patient), 
      medications: finalMeds, 
      followUpConfig: {
        ...formData.followUpConfig!,
        items: finalItems
      },
      id: initialData?.id || crypto.randomUUID(), 
      createdAt: initialData?.createdAt || Date.now() 
    });
  };

  const toggleItem = (item: string) => {
    const items = formData.followUpConfig?.items || [];
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { 
        ...prev.followUpConfig!, 
        items: items.includes(item) ? items.filter(i => i !== item) : [...items, item] 
      } 
    }));
  };

  return (
    <form onSubmit={handleSubmit} className="glass rounded-[2.5rem] p-8 space-y-10 animate-fade-in overflow-y-auto max-h-[85vh] shadow-2xl text-gray-900 border-white/40">
      <div className="flex justify-between items-center pb-6 border-b border-white/30">
        <div>
           <h2 className="text-3xl font-black text-gray-900 tracking-tight">
             {initialData ? '更新患儿档案' : '儿科病例录入'}
           </h2>
           <p className="text-violet-500 text-xs font-black uppercase tracking-[0.2em] mt-1">
             Pediatric Clinical Records
           </p>
        </div>
        <button type="button" onClick={onCancel} className="p-3 bg-black/5 hover:bg-black/10 rounded-full transition-colors">
          <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
      </div>

      <div className="space-y-12">
        {/* 基本身份信息 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-violet-500 rounded-full"></div>
             <h3 className="text-lg font-bold">基本身份信息</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6 bg-white/40 p-8 rounded-[2rem] border border-white/50 shadow-inner">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">患儿姓名</label>
              <input name="name" value={formData.name} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20 outline-none transition-all font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">性别</label>
              <select name="gender" value={formData.gender} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold">
                <option value={Gender.MALE}>男 (Boy)</option>
                <option value={Gender.FEMALE}>女 (Girl)</option>
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">当前年龄</label>
              <input type="number" name="age" value={formData.age} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-fuchsia-500 uppercase tracking-widest px-1">过敏史</label>
              <input name="allergies" value={formData.allergies} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-fuchsia-500/20 outline-none transition-all font-semibold" placeholder="药物/食物过敏情况" />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-sky-500 uppercase tracking-widest px-1">家族史</label>
              <input name="familyHistory" value={formData.familyHistory} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-sky-500/20 outline-none transition-all font-semibold" placeholder="癫痫/遗传病史" />
            </div>
          </div>
        </section>

        {/* 临床概况 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-sky-400 rounded-full"></div>
             <h3 className="text-lg font-bold">临床概况与医学检查</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">临床诊断</label>
                <input name="diagnosis" value={formData.diagnosis} onChange={handleInputChange} className="w-full px-6 py-5 bg-white/80 border-2 border-sky-400/30 rounded-2xl shadow-sm outline-none font-black text-lg text-sky-700" placeholder="如: 局灶性癫痫" required />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">癫痫综合征</label>
                <input name="clinicalSummary.syndrome" value={formData.clinicalSummary?.syndrome} onChange={handleInputChange} className="w-full px-6 py-5 bg-white/80 border-2 border-violet-500/30 rounded-2xl shadow-sm outline-none font-black text-lg text-violet-700" placeholder="如: West 综合征" />
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">发作形式特征</label>
              <textarea name="clinicalSummary.seizureType" value={formData.clinicalSummary?.seizureType} onChange={handleInputChange} className="w-full px-6 py-4 bg-white/60 rounded-2xl outline-none min-h-[80px] text-sm font-medium" placeholder="描述发作的具体动作、持续时间、伴随症状等..." />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-violet-400 uppercase tracking-widest">脑电图 (EEG)</label>
                <textarea name="clinicalSummary.eeg" value={formData.clinicalSummary?.eeg} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px] focus:ring-2 focus:ring-violet-300" placeholder="描述脑电特征..." />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-sky-400 uppercase tracking-widest">头颅 MRI/影像</label>
                <textarea name="clinicalSummary.mri" value={formData.clinicalSummary?.mri} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px] focus:ring-2 focus:ring-sky-300" placeholder="描述影像学表现..." />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">基因/代谢筛选</label>
                <textarea name="clinicalSummary.genetic" value={formData.clinicalSummary?.genetic} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[120px] focus:ring-2 focus:ring-fuchsia-300" placeholder="记录基因检测结果..." />
              </div>
            </div>
          </div>
        </section>

        {/* 治疗与药物方案 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-fuchsia-500 rounded-full"></div>
             <h3 className="text-lg font-bold">治疗与药物方案</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0">
             <div className="space-y-6">
                {(formData.medications || []).map((med, idx) => {
                  const isKnown = COMMON_MEDICATIONS.includes(med.name);
                  const showManualInput = !isKnown && med.name !== '';

                  return (
                    <div key={idx} className="bg-white/50 p-6 rounded-3xl border border-white/50 space-y-4 shadow-sm relative group">
                      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 items-end">
                        <div className="lg:col-span-5 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">药物名称 (ASM)</label>
                          <select 
                            value={isKnown ? med.name : (med.name === '' ? '' : 'OTHER')}
                            onChange={(e) => {
                              const val = e.target.value;
                              if (val === 'OTHER') handleMedicationChange(idx, 'name', ' '); 
                              else handleMedicationChange(idx, 'name', val);
                            }}
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-bold border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20"
                          >
                            <option value="">选择药物...</option>
                            {COMMON_MEDICATIONS.map(m => <option key={m} value={m}>{m}</option>)}
                            <option value="OTHER">其他 (手动输入)...</option>
                          </select>
                          {showManualInput && (
                            <input 
                              autoFocus
                              value={med.name === ' ' ? '' : med.name}
                              onChange={(e) => handleMedicationChange(idx, 'name', e.target.value)}
                              className="w-full px-4 py-4 mt-2 bg-violet-50/50 border-2 border-violet-200 rounded-xl outline-none text-sm font-black text-violet-700"
                              placeholder="手动输入药物名称"
                            />
                          )}
                        </div>

                        <div className="lg:col-span-3 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">用法</label>
                          <input 
                            value={med.usage} 
                            onChange={(e) => handleMedicationChange(idx, 'usage', e.target.value)} 
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20" 
                            placeholder="如: 口服 bid" 
                          />
                        </div>

                        <div className="lg:col-span-3 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">用量</label>
                          <input 
                            value={med.amount} 
                            onChange={(e) => handleMedicationChange(idx, 'amount', e.target.value)} 
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20" 
                            placeholder="如: 0.25g" 
                          />
                        </div>

                        <div className="lg:col-span-1 pb-1 flex justify-center">
                          <button 
                            type="button" 
                            onClick={() => setFormData(p => ({ ...p, medications: p.medications?.filter((_, i) => i !== idx) }))} 
                            className="p-3 bg-fuchsia-50 text-fuchsia-500 rounded-xl hover:bg-fuchsia-500 hover:text-white transition-all"
                          >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                          </button>
                        </div>
                      </div>
                    </div>
                  );
                })}
                <button 
                  type="button" 
                  onClick={() => setFormData(p => ({ ...p, medications: [...(p.medications || []), { name: '', usage: '', amount: '' }] }))} 
                  className="w-full py-5 bg-violet-50 text-violet-600 font-black rounded-3xl hover:bg-violet-100 transition-all text-sm border-2 border-dashed border-violet-200"
                >
                  + 添加治疗药物
                </button>
             </div>
          </div>
        </section>

        {/* 儿科随访管理 */}
        <section className="bg-white/50 p-8 rounded-[2.5rem] border border-white shadow-sm">
           <h3 className="text-xl font-bold mb-8 flex items-center gap-2">
             <svg className="w-6 h-6 text-sky-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             儿科随访管理
           </h3>
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="space-y-4">
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                   {FOLLOW_UP_ITEMS.map(item => (
                     <div 
                      key={item} 
                      onClick={() => toggleItem(item)} 
                      className={`p-3 rounded-2xl border-2 transition-all cursor-pointer flex items-center justify-center text-center text-[10px] font-black leading-tight uppercase tracking-widest ${formData.followUpConfig?.items.includes(item) ? 'bg-violet-600 border-violet-600 text-white shadow-lg' : 'bg-white border-black/5 text-gray-400 hover:border-violet-200'}`}
                     >
                       {item}
                     </div>
                   ))}
                </div>
                {formData.followUpConfig?.items.includes('其他') && (
                  <div className="animate-fade-in space-y-1.5">
                    <label className="text-[10px] font-black text-violet-500 uppercase tracking-widest ml-1">自定义随访内容</label>
                    <input 
                      type="text"
                      value={otherFollowUpText}
                      onChange={(e) => setOtherFollowUpText(e.target.value)}
                      placeholder="请输入具体的随访内容..."
                      className="w-full px-5 py-4 bg-white border-2 border-violet-100 rounded-2xl outline-none font-bold text-sm shadow-sm"
                    />
                  </div>
                )}
              </div>

              <div className="space-y-8">
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">随访间隔 (月)</label>
                       <input type="number" name="followUpConfig.intervalMonths" value={formData.followUpConfig?.intervalMonths} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-bold focus:ring-2 focus:ring-violet-200" />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">本次就诊日期</label>
                       <input type="date" name="followUpConfig.lastFollowUpDate" value={formData.followUpConfig?.lastFollowUpDate} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-bold text-sm focus:ring-2 focus:ring-violet-200" />
                    </div>
                 </div>
                 <div className="p-8 bg-gradient-to-br from-violet-600 to-sky-600 rounded-[2rem] text-white shadow-xl">
                    <span className="text-xs font-black text-violet-100 uppercase tracking-[0.2em] block mb-2">Next Appointment</span>
                    <span className="text-3xl font-black">{formData.followUpConfig?.nextFollowUpDate || '系统自动生成...'}</span>
                 </div>
              </div>
           </div>
        </section>
      </div>

      <div className="flex gap-6 pt-10 sticky bottom-0 bg-white/30 backdrop-blur-md -mx-8 px-8 pb-4 z-20">
        <button type="submit" className="flex-1 bg-violet-600 text-white font-black py-5 rounded-3xl shadow-2xl hover:bg-violet-700 transition-all text-lg active:scale-95">
          确认存档
        </button>
        <button type="button" onClick={onCancel} className="px-12 py-5 bg-white/80 text-gray-700 font-bold rounded-3xl hover:bg-white transition-all text-lg shadow-sm">
          取消
        </button>
      </div>
    </form>
  );
};

export default PatientForm;
